      setCloudSyncState('saving', `云端数据较大（${formatBackupBytes(getCloudBackupBytes(meta))}），已切换为后台缓慢同步`, updatedAt);
      queueDeferredCloudRestore(meta, { forceOverwriteLocal: true });
