// ============================================================
// 筛选
// ============================================================
function getTaskFilterLabel(mode){
  const key = String(mode || 'all');
  if (key === 'diagnose') return '待判因';
  if (key === 'review_ready') return '待复盘';
  if (key === 'retrain') return '待复训';
  return '全部任务';
}
function matchTaskFilter(errorLike, mode){
  const key = String(mode || 'all');
  if (key === 'all') return true;
  const e = typeof normalizeErrorForWorkflow === 'function' ? normalizeErrorForWorkflow({ ...(errorLike || {}) }) : (errorLike || {});
  const stage = String(e.workflowStage || '');
  if (key === 'diagnose') return stage === 'captured' || stage === 'diagnosing';
  if (key === 'review_ready') return stage === 'review_ready';
  if (key === 'retrain') return stage === 'retrain_due';
  return true;
}
function setTaskFilter(mode){
  taskFilter = ['diagnose', 'review_ready', 'retrain'].includes(String(mode || '')) ? String(mode) : 'all';
  statusFilter='all';
  typeFilter=null;
  reasonFilter=null;
  knowledgeNodeFilter=null;
  searchKw='';
  dateFrom='';
  dateTo='';
  const searchInput = document.getElementById('searchInput');
  const dateFromInput = document.getElementById('dateFrom');
  const dateToInput = document.getElementById('dateTo');
  if (searchInput) searchInput.value = '';
  if (dateFromInput) dateFromInput.value = '';
  if (dateToInput) dateToInput.value = '';
  if (typeof updateSearchClear === 'function') updateSearchClear();
  renderSidebar();
  renderAll();
}
function setStatusFilter(s){ taskFilter='all';statusFilter=s;typeFilter=null;knowledgeNodeFilter=null;renderSidebar();renderAll(); }
function setTypeFilter(t){ taskFilter='all';typeFilter={level:'type',value:t};knowledgeNodeFilter=null;renderSidebar();renderAll(); }
function setSubFilter(t,s){ taskFilter='all';typeFilter={level:'subtype',type:t,value:s};knowledgeNodeFilter=null;renderSidebar();renderAll(); }
function setReasonFilter(r){ taskFilter='all';reasonFilter=(reasonFilter===r)?null:r; knowledgeNodeFilter=null; renderSidebar();renderAll(); }

// ---- 错因表单逻辑（大类过滤 + 自由手填）----
function initReasonCatSelect(){
  const sel = document.getElementById('editReasonCat');
  if(!sel || sel.options.length > 1) return;
  REASON_GROUPS.forEach(g=>{
    const o = document.createElement('option');
    o.value = g.label;
    o.textContent = g.label;
    sel.appendChild(o);
  });
}
function rebuildReasonDatalist(cat){
  const dl = document.getElementById('editReasonDatalist');
  if(!dl) return;
  dl.innerHTML = '';
  const groups = cat ? REASON_GROUPS.filter(g=>g.label===cat) : REASON_GROUPS;
  groups.forEach(g=>{
    g.reasons.forEach(r=>{
      const o = document.createElement('option');
      o.value = r.v;
      o.label = r.d;  // 部分浏览器会显示为提示
      dl.appendChild(o);
    });
  });
}
function onReasonCatChange(){
  const cat = document.getElementById('editReasonCat').value;
  rebuildReasonDatalist(cat);
  // 切换大类后清空当前值（如果当前值不属于新大类）
  const cur = document.getElementById('editErrorReason').value.trim();
  if(cur && cat){
    const g = getReasonGroup(cur);
    if(!g || g.label !== cat) document.getElementById('editErrorReason').value = '';
  }
  updateReasonDesc();
}
function updateReasonDesc(){
  const v = document.getElementById('editErrorReason').value.trim();
  const descBox = document.getElementById('editReasonDescBox');
  if(!v){ descBox.style.display='none'; return; }
  const d = getReasonDesc(v);
  const g = getReasonGroup(v);
  if(d){
    descBox.innerHTML = (g ? `<span style="color:${g.color};font-weight:600">${escapeHtml(g.label)}</span> · ` : '') + escapeHtml(d);
    descBox.style.display = '';
  } else {
    descBox.style.display = 'none';
  }
}
function setReasonFormValue(reason){
  rebuildReasonDatalist('');   // 全量 datalist 作提示
  const inp = document.getElementById('editErrorReason');
  if(inp) inp.value = reason||'';
  updateReasonDesc();
}
function setSub2Filter(t,s,s2){
  if (typeFilter && typeFilter.level==='sub2' && typeFilter.type===t && typeFilter.subtype===s) {
    typeFilter = null;
  } else {
    typeFilter={level:'sub2',type:t,subtype:s,value:s2};
  }
  taskFilter='all';
  knowledgeNodeFilter=null;
  renderSidebar();renderAll();
}
function toggleExpSubtype(t,s){
  const k='sub:'+t+'::'+s;
  if(expTypes.has(k)) expTypes.delete(k); else expTypes.add(k);
  saveExpTypes(); renderSidebar();
}
function onSearch(){
  searchKw=document.getElementById('searchInput').value.trim();
  // 高亮匹配项（可选：在菜单项中用 hl 函数高亮）
  renderAll();
}
function clearFilter(){ taskFilter='all';statusFilter='all';typeFilter=null;reasonFilter=null;knowledgeNodeFilter=null;searchKw='';dateFrom='';dateTo='';document.getElementById('searchInput').value='';document.getElementById('dateFrom').value='';document.getElementById('dateTo').value='';updateSearchClear();renderSidebar();renderAll(); }
function getFiltered(){
  return getErrorEntries().filter(e=>{
    if(!matchTaskFilter(e, taskFilter)) return false;
    if(statusFilter!=='all' && normalizeErrorStatusValue(e.status)!==statusFilter) return false;
    if(knowledgeNodeFilter){
      const currentNode = getKnowledgeNodeById(knowledgeNodeFilter);
      const nodeIds = currentNode ? getKnowledgeDescendantNodeIds(currentNode) : [knowledgeNodeFilter];
      if(!nodeIds.includes(e.noteNodeId)) return false;
    }
    if(typeFilter){
      if(typeFilter.level==='type'&&e.type!==typeFilter.value)return false;
      if(typeFilter.level==='subtype'&&(e.type!==typeFilter.type||e.subtype!==typeFilter.value))return false;
      if(typeFilter.level==='sub2'&&(e.type!==typeFilter.type||e.subtype!==typeFilter.subtype||e.subSubtype!==typeFilter.value))return false;
    }
    if(reasonFilter && (e.rootReason||e.errorReason||'').trim() !== reasonFilter) return false;
    if(searchKw){
      const terms=searchKw.toLowerCase().split(/\s+/).filter(Boolean);
      const text=(e.question+' '+(e.options||'')+' '+(e.analysis||'')+' '+e.type+' '+(e.subtype||'')+' '+(e.subSubtype||'')+' '+(e.errorReason||'')+' '+(e.rootReason||'')+' '+(e.srcYear||'')+' '+(e.srcProvince||'')+' '+(e.srcOrigin||'')).toLowerCase();
      // 多关键词 AND 子串匹配：空格分隔多个词，每个词都必须出现在题目中
      if(!terms.every(t=>text.includes(t)))return false;
    }
    if(dateFrom && e.addDate && e.addDate < dateFrom) return false;
    if(dateTo   && e.addDate && e.addDate > dateTo)   return false;
    return true;
  });
}

window.getTaskFilterLabel = getTaskFilterLabel;
window.matchTaskFilter = matchTaskFilter;
/* END: modules/main/15-filters.js */

/* BEGIN: modules/main/16-main-render.js */
// ============================================================
// 渲染主列表
// ============================================================
const INITIAL_ERROR_RENDER_LIMIT = 60;
const ERROR_RENDER_STEP = 60;
let errorRenderLimit = INITIAL_ERROR_RENDER_LIMIT;
let errorRenderKey = '';
let errorListAutoPagerObserver = null;

function getErrorRenderStateKey(list){
  return JSON.stringify({
    size: Array.isArray(list) ? list.length : 0,
    searchKw: String(searchKw || ''),
    statusFilter: String(statusFilter || ''),
    taskFilter: String(taskFilter || ''),
    reasonFilter: String(reasonFilter || ''),
    typeFilter: typeFilter || null
  });
}

function resetErrorRenderWindow(){
  errorRenderLimit = INITIAL_ERROR_RENDER_LIMIT;
}

function shouldUseProgressiveErrorRender(list){
  if (!Array.isArray(list)) return false;
  if (list.length > 120) return true;
  if (typeof isLikelyMobileLikeDevice === 'function' && isLikelyMobileLikeDevice() && list.length > 40) return true;
  return false;
}

function loadMoreErrors(){
  errorRenderLimit += ERROR_RENDER_STEP;
  renderAll();
}

function disconnectErrorListAutoPager(){
  if (errorListAutoPagerObserver) {
    errorListAutoPagerObserver.disconnect();
    errorListAutoPagerObserver = null;
  }
}

function attachErrorListAutoPager(){
  disconnectErrorListAutoPager();
  const sentinel = document.getElementById('errorListAutoPager');
  if (!sentinel || typeof IntersectionObserver === 'undefined') return;
  errorListAutoPagerObserver = new IntersectionObserver((entries) => {
    const hit = entries.some(entry => entry.isIntersecting);
    if (!hit) return;
    disconnectErrorListAutoPager();
    loadMoreErrors();
  }, {
    root: null,
    rootMargin: '240px 0px',
    threshold: 0.01
  });
  errorListAutoPagerObserver.observe(sentinel);
}

function renderTaskFilterBar(){
  const host = document.getElementById('taskFilterBar');
  if(!host) return;
  const allEntries = getErrorEntries();
  const items = [
    { key:'all', label:'全部', count:allEntries.length },
    { key:'diagnose', label:'待判因', count:allEntries.filter(e => matchTaskFilter(e, 'diagnose')).length },
    { key:'review_ready', label:'待复盘', count:allEntries.filter(e => matchTaskFilter(e, 'review_ready')).length },
    { key:'retrain', label:'待复训', count:allEntries.filter(e => matchTaskFilter(e, 'retrain')).length },
  ];
  host.innerHTML = items.map(item => `
    <button class="btn btn-sm ${taskFilter===item.key?'btn-primary':'btn-secondary'}" onclick="setTaskFilter('${item.key}')">
      ${escapeHtml(item.label)}（${item.count}）
    </button>
  `).join('');
}
function renderStats(list){
  renderTaskFilterBar();
  const f=list.filter(e=>normalizeErrorStatusValue(e.status)==='focus').length;
  const r=list.filter(e=>normalizeErrorStatusValue(e.status)==='review').length;
  const m=list.filter(e=>normalizeErrorStatusValue(e.status)==='mastered').length;
  document.getElementById('statsBar').innerHTML=`
    <div class="stat-item"><div class="stat-num">${list.length}</div><div class="stat-label">共计</div></div>
    <div class="stat-item"><div class="stat-num" style="color:#e74c3c">${f}</div><div class="stat-label">重点</div></div>
    <div class="stat-item"><div class="stat-num" style="color:#fa8c16">${r}</div><div class="stat-label">待复习</div></div>
    <div class="stat-item"><div class="stat-num" style="color:#52c41a">${m}</div><div class="stat-label">已掌握</div></div>`;
  let crumb='全部题目';
  if(typeFilter){
    if(typeFilter.level==='type') crumb=typeFilter.value;
    else if(typeFilter.level==='subtype') crumb=`${typeFilter.type} › ${typeFilter.value}`;
    else if(typeFilter.level==='sub2') crumb=`${typeFilter.type} › ${typeFilter.subtype} › ${typeFilter.value}`;
  } else if(taskFilter!=='all') {
    crumb=`任务视角：${getTaskFilterLabel(taskFilter)}`;
  } else if(statusFilter!=='all') crumb=getErrorStatusLabel(statusFilter);
  if(reasonFilter) crumb+=(crumb==='全部题目'?'':`，`)+'错因: '+reasonFilter;
  if(searchKw) crumb+=` › 搜索"${escapeHtml(searchKw)}"`;
  document.getElementById('breadcrumb').innerHTML=crumb==='全部题目'?'全部题目':
    `全部 › <span>${escapeHtml(crumb)}</span> <span style="cursor:pointer;color:#aaa;font-size:11px;margin-left:4px" onclick="clearFilter()">✕ 清除</span>`;
}

function renderAll(){
  const list=getFiltered();
  const currentRenderKey = getErrorRenderStateKey(list);
  if(currentRenderKey !== errorRenderKey){
    errorRenderKey = currentRenderKey;
    resetErrorRenderWindow();
  }
  renderStats(list);
  if(!list.length){
    disconnectErrorListAutoPager();
    document.getElementById('errorList').innerHTML=`<div class="empty"><div class="emoji">${searchKw?'🔍':'📭'}</div><p>${searchKw?'未找到匹配题目':'暂无错题，点击"＋ 添加"'}</p></div>`;
    if (typeof window.refreshKnowledgeWorkspaceCards === 'function') {
      window.refreshKnowledgeWorkspaceCards();
    }
    if (typeof window.refreshClaudeBankModal === 'function') {
      window.refreshClaudeBankModal();
    }
    return;
  }
  const progressive = shouldUseProgressiveErrorRender(list);
  const visibleList = progressive ? list.slice(0, errorRenderLimit) : list;
  const typeMap={};
  visibleList.forEach(e=>{
    if(!typeMap[e.type]) typeMap[e.type]={};
    const s=e.subtype||'未分类';
    if(!typeMap[e.type][s]) typeMap[e.type][s]=[];
    typeMap[e.type][s].push(e);   // 保持数组，三级分组在渲染时动态分拆
  });
  let html='';
  Object.entries(typeMap).forEach(([type,subs])=>{
    const open=expMain.has(type);
    const total=Object.values(subs).reduce((s,a)=>s+a.length,0);
    html+=`<div class="type-group">
      <div class="type-header" onclick="toggleMain('${escapeHtml(type)}')">
        <div class="type-title">
          <span class="type-arrow ${open?'open':''}">▶</span>
          ${escapeHtml(type)}<span class="type-badge">${total}</span>
        </div>
      </div>`;
    if(open){
      Object.entries(subs).forEach(([sub,cards])=>{
        const sk='sub:'+type+'::'+sub;
        const sopen=expMainSub.has(sk);
        // 按三级分组
        const sub2Map={};
        cards.forEach(e=>{
          const s2=e.subSubtype||'';
          if(!sub2Map[s2]) sub2Map[s2]=[];
          sub2Map[s2].push(e);
        });
        const hasSub2=Object.keys(sub2Map).some(k=>k!=='');
        html+=`<div class="subtype-group">
          <div class="subtype-header" onclick="toggleMainSub('${escapeHtml(type)}','${escapeHtml(sub)}')">
            <div class="subtype-title">
              <span class="subtype-arrow ${sopen?'open':''}">▶</span>
              ${escapeHtml(sub)}
              <span style="font-size:11px;color:#aaa;background:#f0f0f0;padding:1px 6px;border-radius:8px">${cards.length}</span>
            </div>
          </div>`;
        if(sopen){
          if(hasSub2){
            // 无三级分类的先输出
            (sub2Map['']||[]).forEach(e=>{ html+=renderCard(e); });
            Object.entries(sub2Map).forEach(([s2,s2cards])=>{
              if(!s2) return;
              const s2k='s2:'+type+'::'+sub+'::'+s2;
              const s2open=expMainSub2.has(s2k);
              html+=`<div class="sub2-group">
                <div class="sub2-header" onclick="toggleMainSub2('${escapeHtml(type)}','${escapeHtml(sub)}','${escapeHtml(s2)}')">
                  <div class="sub2-title">
                    <span class="sub2-arrow ${s2open?'open':''}">▶</span>
                    ${escapeHtml(s2)}
                    <span style="font-size:10px;color:#bbb;background:#f5f5f5;padding:0 5px;border-radius:5px">${s2cards.length}</span>
                  </div>
                </div>`;
              if(s2open) s2cards.forEach(e=>{ html+=renderCard(e); });
              html+='</div>';
            });
          } else {
            cards.forEach(e=>{ html+=renderCard(e); });
          }
        }
        html+='</div>';
      });
    }
    html+='</div>';
  });
  const el = document.getElementById('errorList');
  if (!el) {
    console.error('[FATAL] errorList container missing');
    return;
  }
  if(progressive && list.length > visibleList.length){
    html += `<div class="home-dashboard-card" style="margin:16px 0 8px">
      <div style="display:flex;align-items:center;justify-content:space-between;gap:12px;flex-wrap:wrap">
        <div style="font-size:13px;color:#64748b">已渲染 ${visibleList.length} / ${list.length} 题，继续加载更多可以避免手机和 iPad 一次性卡住。</div>
        <button class="btn btn-secondary" type="button" onclick="loadMoreErrors()">继续加载 ${Math.min(ERROR_RENDER_STEP, list.length - visibleList.length)} 题</button>
      </div>
      <div id="errorListAutoPager" style="height:1px"></div>
    </div>`;
  }
  el.innerHTML = html;
  el.classList.toggle('batch-mode-on', batchMode);
  if(progressive && list.length > visibleList.length){
    attachErrorListAutoPager();
  } else {
    disconnectErrorListAutoPager();
  }
  if (typeof queueVisiblePracticeSummaryLoad === 'function') {
    queueVisiblePracticeSummaryLoad(visibleList);
  }
  if (typeof hydrateRenderedErrorCardDetails === 'function') {
    hydrateRenderedErrorCardDetails(visibleList);
  }
  if (typeof window.refreshKnowledgeWorkspaceCards === 'function') {
    window.refreshKnowledgeWorkspaceCards();
  }
  if (typeof window.refreshClaudeBankModal === 'function') {
    window.refreshClaudeBankModal();
  }
}

function toggleMain(t){ if(expMain.has(t))expMain.delete(t);else expMain.add(t);saveExpMain();renderAll(); }
function toggleMainSub(t,s){ const k='sub:'+t+'::'+s; if(expMainSub.has(k))expMainSub.delete(k);else expMainSub.add(k);saveExpMain();renderAll(); }
function toggleMainSub2(t,s,s2){ const k='s2:'+t+'::'+s+'::'+s2; if(expMainSub2.has(k))expMainSub2.delete(k);else expMainSub2.add(k);saveExpMain();renderAll(); }

function expandAll(){
  const list=getFiltered();
  const typeMap={};
  list.forEach(e=>{
    if(!typeMap[e.type])typeMap[e.type]={};
    const s=e.subtype||'未分类';
    if(!typeMap[e.type][s])typeMap[e.type][s]=new Set();
    if(e.subSubtype) typeMap[e.type][s].add(e.subSubtype);
  });
  Object.keys(typeMap).forEach(t=>{
    expMain.add(t);
    Object.keys(typeMap[t]).forEach(s=>{
      expMainSub.add('sub:'+t+'::'+s);
      typeMap[t][s].forEach(s2=>expMainSub2.add('s2:'+t+'::'+s+'::'+s2));
    });
  });
  saveExpMain();renderAll();
}
function collapseAll(){
  expMain.clear();expMainSub.clear();expMainSub2.clear();saveExpMain();renderAll();
}

window.loadMoreErrors = loadMoreErrors;
/* END: modules/main/16-main-render.js */

