(function () {
  function normalizeKnowledgeTitle(value, fallback) {
    var text = (value || "").trim();
    return text || fallback;
  }

  function createKnowledgeNode(title, level, isLeaf) {
    return {
      id: newKnowledgeNodeId(),
      title: title,
      level: level,
      contentMd: "",
      updatedAt: "",
      isLeaf: !!isLeaf,
      children: []
    };
  }

  function createDefaultKnowledgeTree() {
    var roots = FIXED_TYPES.map(function (type) { return createKnowledgeNode(type, 1, false); });
    if (!roots.some(function (node) { return node.title === "未分类"; })) {
      roots.push(createKnowledgeNode("未分类", 1, false));
    }
    return { version: 1, roots: roots };
  }

  function getKnowledgeRootNodes() {
    if (!knowledgeTree || !Array.isArray(knowledgeTree.roots)) {
      knowledgeTree = createDefaultKnowledgeTree();
    }
    return knowledgeTree.roots;
  }

  function findKnowledgeNodeById(nodeId, nodes) {
    var list = nodes || getKnowledgeRootNodes();
    for (var i = 0; i < list.length; i += 1) {
      var node = list[i];
      if (node.id === nodeId) return node;
      var found = findKnowledgeNodeById(nodeId, node.children || []);
      if (found) return found;
    }
    return null;
  }

  function getKnowledgeNodeById(nodeId) {
    if (!nodeId) return null;
    return findKnowledgeNodeById(nodeId, getKnowledgeRootNodes());
  }

  function findKnowledgeParent(nodeId, nodes, parent) {
    var list = nodes || getKnowledgeRootNodes();
    for (var i = 0; i < list.length; i += 1) {
      var node = list[i];
      if (node.id === nodeId) return parent || null;
      var found = findKnowledgeParent(nodeId, node.children || [], node);
      if (found) return found;
    }
    return null;
  }

  function ensureKnowledgeChild(children, title, level, isLeaf) {
    var node = (children || []).find(function (item) { return item.title === title; });
    if (!node) {
      node = createKnowledgeNode(title, level, isLeaf);
      children.push(node);
    }
    if (!Array.isArray(node.children)) node.children = [];
    if (typeof node.contentMd !== "string") node.contentMd = "";
    if (typeof node.updatedAt !== "string") node.updatedAt = "";
    node.level = level;
    node.isLeaf = node.children.length === 0;
    return node;
  }

  function walkKnowledgeNodes(nodes, visitor, trail) {
    (nodes || []).forEach(function (node) {
      var nextTrail = (trail || []).concat(node);
      visitor(node, nextTrail);
      walkKnowledgeNodes(node.children || [], visitor, nextTrail);
    });
  }

  function syncKnowledgeNotesFromTree() {
    var next = {};
    walkKnowledgeNodes(getKnowledgeRootNodes(), function (node) {
      next[node.id] = {
        title: node.title,
        content: node.contentMd || "",
        updatedAt: node.updatedAt || ""
      };
    });
    knowledgeNotes = next;
  }

  function normalizeKnowledgeNodes(nodes, level) {
    (nodes || []).forEach(function (node) {
      if (!node.id) node.id = newKnowledgeNodeId();
      node.title = normalizeKnowledgeTitle(node.title, "知识点-" + node.id.slice(-4));
      node.level = level;
      if (!Array.isArray(node.children)) node.children = [];
      var legacy = knowledgeNotes && knowledgeNotes[node.id];
      if (typeof node.contentMd !== "string") {
        node.contentMd = legacy && typeof legacy.content === "string" ? legacy.content : "";
      }
      if (typeof node.updatedAt !== "string") {
        node.updatedAt = legacy && typeof legacy.updatedAt === "string" ? legacy.updatedAt : "";
      }
      normalizeKnowledgeNodes(node.children, level + 1);
      node.isLeaf = node.children.length === 0;
    });
  }

  function getKnowledgePathConfig(type, subtype, subSubtype) {
    return {
      rootTitle: normalizeKnowledgeTitle(type, "未分类"),
      subTitle: normalizeKnowledgeTitle(subtype, "未分类"),
      sub2Title: normalizeKnowledgeTitle(subSubtype, "未细分")
    };
  }

  function ensureKnowledgeBranchPath(type, subtype, subSubtype) {
    var path = getKnowledgePathConfig(type, subtype, subSubtype);
    var roots = getKnowledgeRootNodes();
    var root = ensureKnowledgeChild(roots, path.rootTitle, 1, false);
    var sub = ensureKnowledgeChild(root.children, path.subTitle, 2, false);
    var sub2 = ensureKnowledgeChild(sub.children, path.sub2Title, 3, false);
    return { root: root, sub: sub, sub2: sub2 };
  }

  function ensureKnowledgeNoteRecord(leafNode) {
    if (!leafNode) return false;
    var changed = false;
    if (typeof leafNode.contentMd !== "string") {
      leafNode.contentMd = "";
      changed = true;
    }
    if (typeof leafNode.updatedAt !== "string") {
      leafNode.updatedAt = "";
      changed = true;
    }
    if (!knowledgeNotes[leafNode.id]) {
      knowledgeNotes[leafNode.id] = {
        title: leafNode.title,
        content: leafNode.contentMd || "",
        updatedAt: leafNode.updatedAt || ""
      };
      changed = true;
    }
    return changed;
  }

  function getKnowledgeLeafDefaultTitle(type, subtype, subSubtype) {
    return normalizeKnowledgeTitle(subSubtype, normalizeKnowledgeTitle(subtype, normalizeKnowledgeTitle(type, "未分类")));
  }

  function ensureKnowledgeLeaf(type, subtype, subSubtype, leafTitle) {
    var path = ensureKnowledgeBranchPath(type, subtype, subSubtype);
    var title = normalizeKnowledgeTitle(leafTitle, getKnowledgeLeafDefaultTitle(type, subtype, subSubtype));
    var leaf = ensureKnowledgeChild(path.sub2.children, title, 4, true);
    if (!leaf.contentMd) {
      leaf.contentMd = "# " + leaf.title + "\n\n";
      leaf.updatedAt = new Date().toISOString();
    }
    ensureKnowledgeNoteRecord(leaf);
    return leaf;
  }

  function collectKnowledgeLeaves(nodes, bucket) {
    var list = nodes || getKnowledgeRootNodes();
    var acc = bucket || [];
    list.forEach(function (node) {
      if (!node.children || node.children.length === 0) acc.push(node);
      collectKnowledgeLeaves(node.children || [], acc);
    });
    return acc;
  }

  function collectKnowledgeNodes(nodes, bucket) {
    var list = nodes || getKnowledgeRootNodes();
    var acc = bucket || [];
    list.forEach(function (node) {
      acc.push(node);
      collectKnowledgeNodes(node.children || [], acc);
    });
    return acc;
  }

  function getKnowledgeDescendantNodeIds(node) {
    if (!node) return [];
    var ids = [node.id];
    (node.children || []).forEach(function (child) {
      ids = ids.concat(getKnowledgeDescendantNodeIds(child));
    });
    return ids;
  }

  function countErrorsForKnowledgeNode(nodeId, includeDescendants) {
    var node = getKnowledgeNodeById(nodeId);
    if (!node) return 0;
    var nodeIds = includeDescendants === false ? [node.id] : getKnowledgeDescendantNodeIds(node);
    return errors.filter(function (item) { return nodeIds.includes(item.noteNodeId); }).length;
  }

  function getKnowledgeAssignableNodesForPath(type, subtype, subSubtype) {
    var path = getKnowledgePathConfig(type, subtype, subSubtype);
    var root = getKnowledgeRootNodes().find(function (node) { return node.title === path.rootTitle; });
    var sub = root && (root.children || []).find(function (node) { return node.title === path.subTitle; });
    var sub2 = sub && (sub.children || []).find(function (node) { return node.title === path.sub2Title; });
    if (!sub2) return [];
    var list = [sub2];
    walkKnowledgeNodes(sub2.children || [], function (node) { list.push(node); });
    return list;
  }

  function getKnowledgePathTitles(nodeId) {
    function walk(nodes, parentTrail) {
      for (var i = 0; i < nodes.length; i += 1) {
        var node = nodes[i];
        var next = parentTrail.concat(node.title);
        if (node.id === nodeId) return next;
        var found = walk(node.children || [], next);
        if (found) return found;
      }
      return null;
    }
    return walk(getKnowledgeRootNodes(), []) || [];
  }

  function collapseKnowledgePathTitles(titles) {
    return (titles || []).filter(function (title, idx, arr) {
      return idx === 0 || title !== arr[idx - 1];
    });
  }

  function getKnowledgeDisplayNode(node) {
    return node || null;
  }

  function resolveKnowledgeDisplayNodeId(nodeId) {
    return nodeId;
  }

  function ensureKnowledgeBindingForError(errorItem) {
    if (!errorItem) return false;
    var bound = getKnowledgeNodeById(errorItem.noteNodeId);
    if (bound) {
      return ensureKnowledgeNoteRecord(bound);
    }
    var branch = ensureKnowledgeBranchPath(errorItem.type, errorItem.subtype, errorItem.subSubtype);
    ensureKnowledgeNoteRecord(branch.sub2);
    errorItem.noteNodeId = branch.sub2.id;
    return true;
  }

  function ensureKnowledgeExpandedDefaults() {
    if (knowledgeExpandedLoaded) return;
    getKnowledgeRootNodes().forEach(function (node) { knowledgeExpanded.add(node.id); });
    knowledgeExpandedLoaded = true;
  }

  function ensureKnowledgeState(opts) {
    var options = opts || {};
    getKnowledgeRootNodes();
    knowledgeNotes = knowledgeNotes && typeof knowledgeNotes === "object" ? knowledgeNotes : {};
    normalizeKnowledgeNodes(getKnowledgeRootNodes(), 1);
    ensureKnowledgeExpandedDefaults();
    var changed = false;
    errors.forEach(function (item) {
      if (ensureKnowledgeBindingForError(item)) changed = true;
    });
    var allNodes = collectKnowledgeNodes();
    if ((!selectedKnowledgeNodeId || !getKnowledgeNodeById(selectedKnowledgeNodeId)) && allNodes.length > 0) {
      selectedKnowledgeNodeId = allNodes[0].id;
    }
    syncKnowledgeNotesFromTree();
    if (options.persist && changed) saveData();
    if (options.persist) saveKnowledgeState();
  }

  function findKnowledgeBranchForModal(createIfMissing) {
    var type = document.getElementById("editType") ? document.getElementById("editType").value : "";
    var subtype = document.getElementById("editSubtype") ? document.getElementById("editSubtype").value.trim() : "";
    var subSubtype = document.getElementById("editSubSubtype") ? document.getElementById("editSubSubtype").value.trim() : "";
    if (createIfMissing) {
      return ensureKnowledgeBranchPath(type, subtype, subSubtype).sub2;
    }
    var path = getKnowledgePathConfig(type, subtype, subSubtype);
    var root = getKnowledgeRootNodes().find(function (node) { return node.title === path.rootTitle; });
    var sub = root && (root.children || []).find(function (node) { return node.title === path.subTitle; });
    return sub && (sub.children || []).find(function (node) { return node.title === path.sub2Title; });
  }

  function expandKnowledgePath(nodeId) {
    var current = getKnowledgeNodeById(nodeId);
    while (current) {
      knowledgeExpanded.add(current.id);
      current = findKnowledgeParent(current.id);
    }
    saveKnowledgeExpanded();
  }

  function isKnowledgeExpanded(node) {
    if (!node || !node.children || !node.children.length) return false;
    return knowledgeExpanded.has(node.id);
  }

  function toggleKnowledgeExpanded(nodeId, event) {
    if (event) event.stopPropagation();
    var node = getKnowledgeNodeById(nodeId);
    if (!node || !node.children || !node.children.length) return;
    if (knowledgeExpanded.has(node.id)) knowledgeExpanded.delete(node.id);
    else knowledgeExpanded.add(node.id);
    saveKnowledgeExpanded();
    renderSidebar();
  }

  function syncKnowledgePickerHint(selectedLeafId) {
    var hint = document.getElementById("editKnowledgeHint");
    if (!hint) return;
    var base = getKnowledgePathConfig(
      document.getElementById("editType") ? document.getElementById("editType").value : "",
      document.getElementById("editSubtype") ? document.getElementById("editSubtype").value.trim() : "",
      document.getElementById("editSubSubtype") ? document.getElementById("editSubSubtype").value.trim() : ""
    );
    var node = selectedLeafId ? getKnowledgeNodeById(selectedLeafId) : null;
    var pathTitles = node
      ? collapseKnowledgePathTitles(getKnowledgePathTitles(node.id)).join(" > ")
      : (base.rootTitle + " > " + base.subTitle + " > " + base.sub2Title);
    hint.textContent = node
      ? (pathTitles + "（保存到当前节点）")
      : (pathTitles + "（保存时默认挂到当前节点）");
  }

  function refreshKnowledgePicker(preferredId) {
    ensureKnowledgeState();
    var select = document.getElementById("editKnowledgeLeaf");
    if (!select) return;
    var nodes = getKnowledgeAssignableNodesForPath(
      document.getElementById("editType") ? document.getElementById("editType").value : "",
      document.getElementById("editSubtype") ? document.getElementById("editSubtype").value.trim() : "",
      document.getElementById("editSubSubtype") ? document.getElementById("editSubSubtype").value.trim() : ""
    );
    var options = ['<option value="">默认挂到当前三级节点</option>']
      .concat(nodes.map(function (node) {
        return '<option value="' + node.id + '">' + escapeHtml(collapseKnowledgePathTitles(getKnowledgePathTitles(node.id)).join(" > ")) + "</option>";
      }));
    select.innerHTML = options.join("");
    if (preferredId && nodes.some(function (node) { return node.id === preferredId; })) {
      select.value = preferredId;
    } else if (nodes.length === 1) {
      select.value = nodes[0].id;
    } else {
      select.value = "";
    }
    syncKnowledgePickerHint(select.value);
  }

  function createKnowledgeLeafFromModal() {
    var branch = findKnowledgeBranchForModal(true);
    var fallback = getKnowledgeLeafDefaultTitle(
      document.getElementById("editType") ? document.getElementById("editType").value : "",
      document.getElementById("editSubtype") ? document.getElementById("editSubtype").value.trim() : "",
      document.getElementById("editSubSubtype") ? document.getElementById("editSubSubtype").value.trim() : ""
    );
    openKnowledgeNodeModal("create-child", {
      parentId: branch.id,
      fallbackTitle: fallback,
      afterSubmit: function (node) { refreshKnowledgePicker(node.id); }
    });
  }

  function resolveKnowledgeNodeIdForSave(type, subtype, subSubtype) {
    var select = document.getElementById("editKnowledgeLeaf");
    var selectedId = select ? select.value : "";
    var selectedNode = selectedId ? getKnowledgeNodeById(selectedId) : null;
    if (selectedNode) {
      ensureKnowledgeNoteRecord(selectedNode);
      selectedKnowledgeNodeId = selectedNode.id;
      return selectedNode.id;
    }
    var branch = ensureKnowledgeBranchPath(type, subtype, subSubtype);
    ensureKnowledgeNoteRecord(branch.sub2);
    selectedKnowledgeNodeId = branch.sub2.id;
    if (select) refreshKnowledgePicker(branch.sub2.id);
    return branch.sub2.id;
  }

  function filterByKnowledgeNode(nodeId) {
    setCurrentKnowledgeNode(nodeId, { switchTab: true });
  }

  function selectKnowledgeNodeFromSidebar(nodeId) {
    setCurrentKnowledgeNode(nodeId, { switchTab: true });
  }

  window.normalizeKnowledgeTitle = normalizeKnowledgeTitle;
  window.createKnowledgeNode = createKnowledgeNode;
  window.createDefaultKnowledgeTree = createDefaultKnowledgeTree;
  window.getKnowledgeRootNodes = getKnowledgeRootNodes;
  window.findKnowledgeNodeById = findKnowledgeNodeById;
  window.getKnowledgeNodeById = getKnowledgeNodeById;
  window.findKnowledgeParent = findKnowledgeParent;
  window.ensureKnowledgeChild = ensureKnowledgeChild;
  window.walkKnowledgeNodes = walkKnowledgeNodes;
  window.syncKnowledgeNotesFromTree = syncKnowledgeNotesFromTree;
  window.normalizeKnowledgeNodes = normalizeKnowledgeNodes;
  window.getKnowledgePathConfig = getKnowledgePathConfig;
  window.ensureKnowledgeBranchPath = ensureKnowledgeBranchPath;
  window.ensureKnowledgeNoteRecord = ensureKnowledgeNoteRecord;
  window.getKnowledgeLeafDefaultTitle = getKnowledgeLeafDefaultTitle;
  window.ensureKnowledgeLeaf = ensureKnowledgeLeaf;
  window.collectKnowledgeLeaves = collectKnowledgeLeaves;
  window.collectKnowledgeNodes = collectKnowledgeNodes;
  window.getKnowledgeDescendantNodeIds = getKnowledgeDescendantNodeIds;
  window.countErrorsForKnowledgeNode = countErrorsForKnowledgeNode;
  window.getKnowledgeAssignableNodesForPath = getKnowledgeAssignableNodesForPath;
  window.getKnowledgePathTitles = getKnowledgePathTitles;
  window.collapseKnowledgePathTitles = collapseKnowledgePathTitles;
  window.getKnowledgeDisplayNode = getKnowledgeDisplayNode;
  window.resolveKnowledgeDisplayNodeId = resolveKnowledgeDisplayNodeId;
  window.ensureKnowledgeBindingForError = ensureKnowledgeBindingForError;
  window.ensureKnowledgeState = ensureKnowledgeState;
  window.findKnowledgeBranchForModal = findKnowledgeBranchForModal;
  window.ensureKnowledgeExpandedDefaults = ensureKnowledgeExpandedDefaults;
  window.expandKnowledgePath = expandKnowledgePath;
  window.isKnowledgeExpanded = isKnowledgeExpanded;
  window.toggleKnowledgeExpanded = toggleKnowledgeExpanded;
  window.syncKnowledgePickerHint = syncKnowledgePickerHint;
  window.refreshKnowledgePicker = refreshKnowledgePicker;
  window.createKnowledgeLeafFromModal = createKnowledgeLeafFromModal;
  window.resolveKnowledgeNodeIdForSave = resolveKnowledgeNodeIdForSave;
  window.filterByKnowledgeNode = filterByKnowledgeNode;
  window.selectKnowledgeNodeFromSidebar = selectKnowledgeNodeFromSidebar;
})();
/* END: modules/knowledge-state.js */

/* BEGIN: modules/knowledge-workbench.js */
(function () {
  function renderSidebarKnowledgeTreeV2(nodes, depth) {
    return (nodes || []).filter(function (node) {
      return typeof isKnowledgeNodeVisibleBySearch !== "function" || isKnowledgeNodeVisibleBySearch(node);
    }).map(function (node) {
      var active = selectedKnowledgeNodeId === node.id || knowledgeNodeFilter === node.id;
      var matched = typeof isKnowledgeNodeSearchMatch === "function" && isKnowledgeNodeSearchMatch(node);
      var count = countErrorsForKnowledgeNode(node.id, true);
      var cls = depth === 0 ? "nav-item nav-type-header" : depth === 1 ? "nav-item nav-subtype" : "nav-item nav-sub2";
      var extraStyle = depth > 2 ? "padding-left:" + (60 + ((depth - 2) * 18)) + "px" : "";
      var hasChildren = !!(node.children && node.children.length);
      var expanded = hasChildren && ((typeof hasKnowledgeTreeSearch === "function" && hasKnowledgeTreeSearch()) || isKnowledgeExpanded(node));
      var marker = hasChildren ? (expanded ? "▾" : "▸") : "·";
      var countClass = count > 0 ? "knowledge-tree-count" : "knowledge-tree-count is-empty";
      var html = "<div class=\"" + cls + " knowledge-tree-node " + (active ? "active is-active" : "") + " " + (matched ? "is-search-match" : "") + " " + (hasChildren ? "is-branch" : "") + "\" style=\"" + extraStyle + "\" data-knowledge-node-id=\"" + node.id + "\" draggable=\"true\" ondragstart=\"startKnowledgeNodeDrag('" + node.id + "', event)\" ondragend=\"endKnowledgeNodeDrag()\" ondragover=\"allowKnowledgeDrop(event, '" + node.id + "')\" ondragleave=\"leaveKnowledgeDrop(event)\" ondrop=\"handleKnowledgeDrop('" + node.id + "', event)\" onclick=\"selectKnowledgeNodeFromSidebar('" + node.id + "')\">" +
        "<span class=\"knowledge-tree-row\">" +
          "<button type=\"button\" class=\"knowledge-tree-toggle" + (hasChildren ? "" : " placeholder") + "\" onclick=\"toggleKnowledgeExpanded('" + node.id + "', event)\" aria-label=\"" + (hasChildren ? "切换展开" : "无下级") + "\">" + marker + "</button>" +
          "<span class=\"knowledge-tree-title\">" + escapeHtml(node.title) + "</span>" +
        "</span>" +
        "<span class=\"" + countClass + "\">" + count + "</span>" +
      "</div>";
      if (hasChildren && expanded) {
        html += "<div class=\"knowledge-tree-children\">" + renderSidebarKnowledgeTreeV2(node.children, depth + 1) + "</div>";
      }
      return html;
    }).join("");
  }

  function setKnowledgeRelatedMode(mode) {
    if (mode !== "direct" && mode !== "all") return;
    knowledgeRelatedMode = mode;
    if (typeof renderNotesByType === "function") {
      renderNotesByType();
    }
  }

  function updateKnowledgeWorkspaceChrome() {
    return;
  }

  function renderKnowledgeNotesPanelRight() {
    var body = document.getElementById("notesPanelRightBody");
    if (body) body.innerHTML = "";
  }

  window.renderSidebarKnowledgeTreeV2 = renderSidebarKnowledgeTreeV2;
  window.setKnowledgeRelatedMode = setKnowledgeRelatedMode;
  window.updateKnowledgeWorkspaceChrome = updateKnowledgeWorkspaceChrome;
  window.renderKnowledgeNotesPanelRight = renderKnowledgeNotesPanelRight;
  window.renderNotesPanelRight = function () {
    renderKnowledgeNotesPanelRight();
  };
})();
/* END: modules/knowledge-workbench.js */

/* BEGIN: modules/knowledge-workspace.js */
(function () {
  var DEFAULT_MODE = "note";

  var TEXT = {
    legacyTypeNotes: "\u65e7\u9898\u578b\u7b14\u8bb0\u5df2\u7ecf\u9000\u5230\u517c\u5bb9\u5c42\uff0c\u5f53\u524d\u7edf\u4e00\u4f7f\u7528\u77e5\u8bc6\u6811\u7b14\u8bb0\u3002",
    noKnowledgeNode: "\u5f53\u524d\u9898\u76ee\u8fd8\u6ca1\u6709\u5173\u8054\u77e5\u8bc6\u70b9",
    pickKnowledgeNode: "\u8bf7\u5148\u9009\u62e9\u4e00\u4e2a\u77e5\u8bc6\u70b9",
    tabQuestions: "\u9898\u76ee",
    tabNotes: "\u7b14\u8bb0",
    countSuffix: "\u9898",
    createQuestion: "+ \u65b0\u5efa\u9898\u76ee",
    standaloneEdit: "\u5f39\u7a97\u7f16\u8f91",
    rename: "\u91cd\u547d\u540d",
    move: "\u79fb\u52a8",
    createChild: "+ \u65b0\u5efa\u4e0b\u7ea7",
    directCount: "\u76f4\u5c5e ",
    linkedCount: "\u542b\u4e0b\u7ea7 ",
    noQuestions: "\u5f53\u524d\u77e5\u8bc6\u70b9\u4e0b\u8fd8\u6ca1\u6709\u9898\u76ee\uff0c\u5148\u70b9\u201c\u65b0\u5efa\u9898\u76ee\u201d\u5f55\u4e00\u9898\u3002",
    currentQuestions: "\u5f53\u524d\u9898\u76ee",
    noNotes: "\u5f53\u524d\u8282\u70b9\u8fd8\u6ca1\u6709\u7b14\u8bb0\uff0c\u5148\u5199\u89c4\u5219\u603b\u7ed3\u3001\u6613\u9519\u70b9\u548c\u4e0b\u4e00\u6b65\u52a8\u4f5c\u3002",
    openStandaloneEditor: "\u6253\u5f00\u5f39\u7a97\u7f16\u8f91\u5668",
    edit: "\u7f16\u8f91",
    done: "\u5b8c\u6210",
    save: "\u4fdd\u5b58",
    shortcutSave: "Ctrl+S \u5feb\u6377\u4fdd\u5b58",
    preview: "\u9884\u89c8",
    currentNote: "\u5f53\u524d\u7b14\u8bb0",
    noKnowledgeContent: "\u6682\u65f6\u8fd8\u6ca1\u6709\u77e5\u8bc6\u70b9\u5185\u5bb9\uff0c\u5148\u5f55\u5165\u9519\u9898\u540e\u4f1a\u81ea\u52a8\u751f\u6210\u7ed3\u6784\u3002"
  };

  function escapeAttr(value) {
    return String(value || "")
      .replace(/&/g, "&amp;")
      .replace(/"/g, "&quot;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;");
  }

  function getWorkspaceMode() {
    if (window.knowledgeWorkspaceMode !== "list" && window.knowledgeWorkspaceMode !== "note") {
      window.knowledgeWorkspaceMode = DEFAULT_MODE;
    }
    return window.knowledgeWorkspaceMode;
  }

  function setWorkspaceMode(mode) {
    window.knowledgeWorkspaceMode = mode === "note" ? "note" : "list";
  }

  function getNoteViewMode() {
    if (window.knowledgeNoteViewMode !== "directory" && window.knowledgeNoteViewMode !== "current") {
      window.knowledgeNoteViewMode = "current";
    }
    return window.knowledgeNoteViewMode;
  }

  function setNoteViewMode(mode) {
    window.knowledgeNoteViewMode = mode === "directory" ? "directory" : "current";
  }

  function getDirectoryPreviewNodeId() {
    return String(window.knowledgeDirectoryPreviewNodeId || "").trim();
  }

  function setDirectoryPreviewNodeId(nodeId) {
    window.knowledgeDirectoryPreviewNodeId = String(nodeId || "").trim();
  }

  function getCurrentKnowledgeNode() {
    return getKnowledgeNodeById(selectedKnowledgeNodeId);
  }

  function getCurrentNoteMarkdown() {
    var ta = document.getElementById("noteTypeTextarea");
    if (ta) return ta.value;
    var node = getCurrentKnowledgeNode();
    return normalizeKnowledgeNoteMarkdown(node ? node.contentMd : "");
  }

  function normalizeKnowledgeNoteMarkdown(value) {
    if (value === null || value === undefined) return "";
    var text = String(value);
    if (text.trim().toLowerCase() === "undefined") return "";
    return text;
  }

  function buildViewerPayload(currentNode, markdown) {
    if (!currentNode) return null;
    return {
      nodeId: currentNode.id,
      title: currentNode.title || "",
      pathText: collapseKnowledgePathTitles(getKnowledgePathTitles(currentNode.id)).join(" > "),
      markdown: markdown || "",
      emptyText: TEXT.noNotes
    };
  }

  function postViewerPayload(frame, payload) {
    if (!frame || !frame.contentWindow || !payload) return;
    try {
      frame.contentWindow.postMessage(
        { type: "knowledge-note-viewer-sync", payload: payload },
        window.location.origin
      );
    } catch (error) {
      console.warn("post viewer payload failed", error);
    }
  }

  function bindViewerFrame(frame) {
    if (!frame || frame.dataset.viewerBound === "1") return;
    frame.dataset.viewerBound = "1";
    frame.addEventListener("load", function () {
      var currentNode = getCurrentKnowledgeNode();
      if (!currentNode) return;
      postViewerPayload(frame, buildViewerPayload(currentNode, getCurrentNoteMarkdown()));
    });
  }

  function syncEmbeddedNoteViewers(currentNode, markdown) {
    var content = document.getElementById("notesContent");
    if (!content || !currentNode) return;
    var payload = buildViewerPayload(currentNode, markdown);
    content.querySelectorAll(".js-note-viewer-frame").forEach(function (frame) {
      bindViewerFrame(frame);
      postViewerPayload(frame, payload);
    });
  }

  function getAvailableNotePreviewHeight(container, host) {
    if (!container || !host) return 0;
    var containerRect = container.getBoundingClientRect();
    var hostRect = host.getBoundingClientRect();
    return Math.max(0, Math.floor(hostRect.bottom - containerRect.top - 12));
  }

  function syncNotePreviewViewportHeight() {
    var container = document.getElementById("noteSplitPreview");
    var host = document.getElementById("notesContent");
    if (!container || !host) return;
    if (!noteEditing) {
      var frame = document.getElementById("noteReadPreviewFrame");
      var contentHeight = frame ? Math.ceil(Number(frame.dataset.contentHeight) || 0) : 0;
      var available = getAvailableNotePreviewHeight(container, host);
      if (frame && contentHeight > 0 && available > 0) {
        var nextHeight = Math.max(120, Math.min(contentHeight, available));
        container.style.height = nextHeight + "px";
        frame.style.height = nextHeight + "px";
      } else if (available > 0) {
        var fallbackHeight = Math.max(260, available);
        container.style.height = fallbackHeight + "px";
        if (frame) frame.style.height = fallbackHeight + "px";
      } else {
        container.style.height = "";
        if (frame) frame.style.height = "";
      }
      container.style.maxHeight = "none";
      return;
    }

    var available = getAvailableNotePreviewHeight(container, host);
    if (available < 260) return;

    container.style.height = available + "px";
    container.style.maxHeight = "none";
  }

  function renderViewerFrame(nodeId, role) {
    var roleName = role || "preview";
    var src = "/assets/note_viewer.html?nodeId=" + encodeURIComponent(nodeId || "") +
      "&embed=1&role=" + encodeURIComponent(roleName);
    return "<iframe" +
      " class=\"note-viewer-frame note-viewer-frame--" + escapeAttr(roleName === "noteSplitPreview" ? "split" : "read") + " js-note-viewer-frame\"" +
      " id=\"" + escapeAttr(roleName) + "Frame\"" +
      " src=\"" + escapeAttr(src) + "\"" +
      " loading=\"lazy\"" +
      " referrerpolicy=\"same-origin\"" +
      " title=\"" + TEXT.preview + "\">" +
    "</iframe>";
  }

  function applyNoteViewerHeight(role, contentHeight) {
    if (role !== "noteReadPreview") return;
    var frame = document.getElementById(role + "Frame");
    if (!frame) return;
    var measuredHeight = Math.max(120, Math.ceil(Number(contentHeight) || 0));
    frame.dataset.contentHeight = String(measuredHeight);
    frame.style.height = measuredHeight + "px";
  }


  function ensureEmbeddedNoteEditorModal() {
    var existing = document.getElementById("knowledgeNoteEditorModal");
    if (existing) return existing;

    var mask = document.createElement("div");
    mask.id = "knowledgeNoteEditorModal";
    mask.className = "modal-mask note-editor-modal-mask";
    mask.innerHTML = "" +
      "<div class=\"note-editor-modal\" role=\"dialog\" aria-modal=\"true\" aria-label=\"" + TEXT.standaloneEdit + "\">" +
        "<button class=\"note-editor-modal-close\" type=\"button\" aria-label=\"Close\">&times;</button>" +
        "<iframe id=\"knowledgeNoteEditorModalFrame\" class=\"note-editor-modal-frame\" title=\"" + TEXT.standaloneEdit + "\"></iframe>" +
      "</div>";

    function requestClose() {
      var frame = document.getElementById("knowledgeNoteEditorModalFrame");
      var editorWindow = frame && frame.contentWindow;
      if (editorWindow && typeof editorWindow.requestNoteEditorClose === "function") {
        if (editorWindow.requestNoteEditorClose(false) === false) return;
      }
      closeEmbeddedKnowledgeNoteEditor(true);
    }

    mask.addEventListener("click", function (event) {
      if (event.target === mask) requestClose();
    });
    mask.querySelector(".note-editor-modal-close").addEventListener("click", requestClose);
    document.addEventListener("keydown", function (event) {
      if (event.key !== "Escape") return;
      if (!mask.classList.contains("open")) return;
      requestClose();
    });

    document.body.appendChild(mask);
    return mask;
  }

  function closeEmbeddedKnowledgeNoteEditor(force) {
    var mask = document.getElementById("knowledgeNoteEditorModal");
    if (!mask) return;
    if (!force) {
      var frame = document.getElementById("knowledgeNoteEditorModalFrame");
      var editorWindow = frame && frame.contentWindow;
      if (editorWindow && typeof editorWindow.requestNoteEditorClose === "function") {
        if (editorWindow.requestNoteEditorClose(false) === false) return;
      }
    }
    mask.classList.remove("open");
    document.body.classList.remove("note-editor-modal-open");
  }

  function collectNodeErrors(currentNode) {
    if (!currentNode) return [];
    var nodeIds = getKnowledgeDescendantNodeIds(currentNode);
    return getFiltered().filter(function (item) {
      return nodeIds.includes(item.noteNodeId);
    });
  }

  function isTopLevelKnowledgeNode(node) {
    if (!node || !node.id) return false;
    return !findKnowledgeParent(node.id);
  }

  function collectDirectorySections(currentNode) {
    if (!currentNode) return [];
    var sections = [];
    var childNodes = (currentNode.children || []).slice();
    childNodes.forEach(function (node) {
      if (!node) return;
      var markdown = normalizeKnowledgeNoteMarkdown(node.contentMd).trim();
      var childCount = countErrorsForKnowledgeNode(node.id, true);
      var hasChildren = !!(node.children && node.children.length);
      if (!markdown && !hasChildren) return;
      sections.push({
        nodeId: node.id,
        title: node.title || "",
        pathText: collapseKnowledgePathTitles(getKnowledgePathTitles(node.id)).join(" > "),
        hasContent: !!markdown,
        hasChildren: hasChildren,
        childCount: childCount
      });
    });
    return sections;
  }

  function buildDirectoryTree(node) {
    if (!node) return null;
    var markdown = normalizeKnowledgeNoteMarkdown(node.contentMd).trim();
    var children = (node.children || []).map(buildDirectoryTree).filter(Boolean);
    var childCount = countErrorsForKnowledgeNode(node.id, true);
    if (!markdown && !children.length) return null;
    return {
      nodeId: node.id,
      title: node.title || "",
      pathText: collapseKnowledgePathTitles(getKnowledgePathTitles(node.id)).join(" > "),
      hasContent: !!markdown,
      childCount: childCount,
      children: children
    };
  }

  function flattenDirectoryTree(tree) {
    var list = [];
    (tree || []).forEach(function walk(node, depth) {
      if (!node) return;
      list.push({
        nodeId: node.nodeId,
        title: node.title,
        pathText: node.pathText,
        hasContent: node.hasContent,
        childCount: node.childCount,
        depth: depth || 0
      });
      (node.children || []).forEach(function (child) {
        walk(child, (depth || 0) + 1);
      });
    });
    return list;
  }

  function getDirectoryPreviewNode(currentNode, sections) {
    var preferredId = getDirectoryPreviewNodeId();
    if (preferredId) {
      var preferred = sections.find(function (section) { return section.nodeId === preferredId; });
      if (preferred) return getKnowledgeNodeById(preferred.nodeId);
    }
    var firstWithContent = sections.find(function (section) { return section.hasContent; });
    var fallback = firstWithContent || sections[0];
    if (!fallback) return null;
    setDirectoryPreviewNodeId(fallback.nodeId);
    return getKnowledgeNodeById(fallback.nodeId);
  }

  function setCurrentKnowledgeNode(nodeId, opts) {
    var options = opts || {};
    if (!nodeId) return;
    var resolvedId = resolveKnowledgeDisplayNodeId(nodeId);
    expandKnowledgePath(resolvedId);
    selectedKnowledgeNodeId = resolvedId;
    knowledgeNodeFilter = options.applyFilter === false ? knowledgeNodeFilter : resolvedId;
    typeFilter = null;
    noteEditing = false;
    if (options.mode) {
      setWorkspaceMode(options.mode);
    } else {
      setWorkspaceMode(DEFAULT_MODE);
    }
    if (options.switchTab !== false) {
      switchTab("notes");
    } else {
      renderSidebar();
      renderAll();
      renderNotesByType();
    }
  }

  function selectKnowledgeLeaf(nodeId) {
    if (!nodeId) return;
    saveNoteTypeContent();
    notesViewMode = "knowledge";
    setCurrentKnowledgeNode(nodeId, { switchTab: false, mode: DEFAULT_MODE });
  }

  function selectNoteType(type) {
    saveNoteTypeContent();
    selectedNoteType = type;
    showToast(TEXT.legacyTypeNotes, "info");
    notesViewMode = "knowledge";
    setWorkspaceMode("note");
    renderNotesByType();
  }

  function openKnowledgeForError(errorId) {
    var errorItem = errors.find(function (item) { return item.id === errorId; });
    if (!errorItem || !errorItem.noteNodeId) {
      showToast(TEXT.noKnowledgeNode, "warning");
      return;
    }
    setCurrentKnowledgeNode(errorItem.noteNodeId, { switchTab: true, mode: "list" });
  }

  function jumpToErrorInList(errorId) {
    switchTab("errors");
    revealed.add(errorId);
    saveReveal();
    renderAll();
    setTimeout(function () {
      var el = document.getElementById("card-" + errorId);
      if (el) el.scrollIntoView({ behavior: "smooth", block: "nearest" });
    }, 50);
  }

  function bindKnowledgeEditorShortcuts(content) {
    var ta = content.querySelector("#noteTypeTextarea");
    if (!ta) return;
    ta.addEventListener("keydown", function (ev) {
      if ((ev.ctrlKey || ev.metaKey) && ev.key === "s") {
        ev.preventDefault();
        saveNoteTypeContent();
      }
    });
  }

  function openExternalKnowledgeNoteEditor(nodeId) {
    ensureKnowledgeState();
    var targetNode = getKnowledgeNodeById(nodeId || selectedKnowledgeNodeId) || getCurrentKnowledgeNode();
    if (!targetNode) {
      showToast(TEXT.pickKnowledgeNode, "warning");
      return;
    }
    var mask = ensureEmbeddedNoteEditorModal();
    var frame = document.getElementById("knowledgeNoteEditorModalFrame");
    if (!frame) return;
    frame.src = "/assets/note_editor.html?nodeId=" + encodeURIComponent(targetNode.id) + "&embed=1";
    mask.classList.add("open");
    document.body.classList.add("note-editor-modal-open");
  }

  function liveNotePreview() {
    var ta = document.getElementById("noteTypeTextarea");
    var currentNode = getCurrentKnowledgeNode();
    if (!ta || !currentNode) return;
    clearGlobalNoteTocDock();
    syncEmbeddedNoteViewers(currentNode, ta.value);
  }

  function saveNoteTypeContent() {
    var ta = document.getElementById("noteTypeTextarea");
    if (!ta) return;
    ensureKnowledgeState();
    if (!selectedKnowledgeNodeId) return;
    var node = getKnowledgeNodeById(selectedKnowledgeNodeId);
    if (!node) return;
    node.contentMd = ta.value;
    node.updatedAt = new Date().toISOString();
    saveKnowledgeState();
  }

  function renderWorkspaceHeader(currentNode, pathText, directCount, linkedCount, errorCount, mode) {
    var backToRecommended = window.__recommendedNotesReturnEnabled
      ? "<button class=\"btn btn-sm btn-secondary\" onclick=\"returnToRecommendedNotes()\">返回推荐列表</button>"
      : "";
    var moreActions = "<details class=\"knowledge-workspace-more\">" +
      "<summary>更多</summary>" +
      "<div class=\"knowledge-workspace-more-menu\">" +
        "<button class=\"btn btn-sm btn-secondary\" onclick=\"openExternalKnowledgeNoteEditor('" + currentNode.id + "')\">" + TEXT.standaloneEdit + "</button>" +
        "<button class=\"btn btn-sm btn-secondary\" onclick=\"renameKnowledgeNode('" + currentNode.id + "')\">" + TEXT.rename + "</button>" +
        (findKnowledgeParent(currentNode.id) ? "<button class=\"btn btn-sm btn-secondary\" onclick=\"moveKnowledgeNode('" + currentNode.id + "')\">" + TEXT.move + "</button>" : "") +
        "<button class=\"btn btn-sm btn-secondary\" onclick=\"selectedKnowledgeNodeId='" + currentNode.id + "';addKnowledgeLeafUnderSelected()\">" + TEXT.createChild + "</button>" +
      "</div>" +
    "</details>";
    return "<div class=\"knowledge-workspace-shell-header\">" +
      "<div class=\"knowledge-workspace-shell-meta\">" +
        "<div class=\"knowledge-workspace-shell-title\">" + escapeHtml(currentNode.title) + "</div>" +
        "<div class=\"knowledge-workspace-shell-path\">" + escapeHtml(pathText) + "</div>" +
      "</div>" +
      "<div class=\"knowledge-workspace-shell-actions\">" +
        "<div class=\"knowledge-workspace-mode-switch\">" +
          "<button class=\"btn btn-sm " + (mode === "list" ? "btn-primary" : "btn-secondary") + "\" onclick=\"setKnowledgeWorkspaceMode('list')\">" + TEXT.tabQuestions + "</button>" +
          "<button class=\"btn btn-sm " + (mode === "note" ? "btn-primary" : "btn-secondary") + "\" onclick=\"setKnowledgeWorkspaceMode('note')\">" + TEXT.tabNotes + "</button>" +
        "</div>" +
        (mode === "note" && isTopLevelKnowledgeNode(currentNode)
          ? "<div class=\"knowledge-workspace-mode-switch knowledge-note-view-switch\">" +
              "<button class=\"btn btn-sm " + (getNoteViewMode() === "current" ? "btn-primary" : "btn-secondary") + "\" onclick=\"setKnowledgeNoteViewMode('current')\">当前笔记</button>" +
              "<button class=\"btn btn-sm " + (getNoteViewMode() === "directory" ? "btn-primary" : "btn-secondary") + "\" onclick=\"setKnowledgeNoteViewMode('directory')\">章节目录</button>" +
            "</div>"
          : "") +
        "<span class=\"knowledge-workspace-count\">" + errorCount + TEXT.countSuffix + "</span>" +
        backToRecommended +
        "<button class=\"btn btn-sm btn-secondary\" onclick=\"openAddModalForCurrentKnowledge()\">" + TEXT.createQuestion + "</button>" +
        moreActions +
      "</div>" +
      "<div class=\"knowledge-workspace-shell-stats\">" +
        "<span class=\"knowledge-workspace-stat\">" + TEXT.directCount + directCount + "</span>" +
        "<span class=\"knowledge-workspace-stat\">" + TEXT.linkedCount + linkedCount + "</span>" +
      "</div>" +
    "</div>";
  }

  function renderListMode(currentNode, relatedErrors) {
    if (typeof queueVisiblePracticeSummaryLoad === "function") {
      queueVisiblePracticeSummaryLoad(relatedErrors);
    }
    var body = relatedErrors.length
      ? relatedErrors.map(function (item) { return renderCard(item); }).join("")
      : "<div class=\"knowledge-workspace-empty\">" + TEXT.noQuestions + "</div>";

    return "<div class=\"knowledge-workspace-list-wrap\">" +
      "<div class=\"knowledge-workspace-list-head\">" + TEXT.currentQuestions + "</div>" +
      "<div class=\"knowledge-workspace-list\">" + body + "</div>" +
    "</div>";
  }

  function ensureKnowledgeWorkspaceListScrollable() {
    var content = document.getElementById("notesContent");
    if (!content) return;
    var shell = content.querySelector(".knowledge-workspace-shell");
    if (!shell) return;
    var listWrap = shell.querySelector(".knowledge-workspace-list-wrap");
    var list = shell.querySelector(".knowledge-workspace-list");
    if (!listWrap || !list) return;
    var shellHeader = shell.querySelector(".knowledge-workspace-shell-header");
    var listHead = listWrap.querySelector(".knowledge-workspace-list-head");
    listWrap.style.display = "flex";
    listWrap.style.flexDirection = "column";
    listWrap.style.flex = "1";
    listWrap.style.minHeight = "0";
    listWrap.style.overflow = "hidden";

    var wrapHeight = listWrap.clientHeight || 0;
    if (wrapHeight < 120) {
      var shellHeight = shell.clientHeight || 0;
      var shellHeaderHeight = shellHeader ? shellHeader.offsetHeight : 0;
      wrapHeight = Math.max(220, shellHeight - shellHeaderHeight - 8);
      listWrap.style.height = wrapHeight + "px";
      listWrap.style.maxHeight = wrapHeight + "px";
    } else {
      listWrap.style.height = "";
      listWrap.style.maxHeight = "";
    }

    var occupied = listHead ? listHead.offsetHeight : 0;
    var availableHeight = Math.max(200, wrapHeight - occupied - 8);
    list.style.minHeight = "200px";
    list.style.height = availableHeight + "px";
    list.style.maxHeight = availableHeight + "px";
    list.style.overflowY = "auto";
    list.style.overflowX = "hidden";
    list.style.touchAction = "pan-y";
    list.style.webkitOverflowScrolling = "touch";
  }

  var __knowledgeWorkspaceScrollListenerBound = false;
  function bindKnowledgeWorkspaceScrollListener() {
    if (__knowledgeWorkspaceScrollListenerBound) return;
    __knowledgeWorkspaceScrollListenerBound = true;
    window.addEventListener("resize", function () {
      var content = document.getElementById("notesContent");
      if (!content || !content.classList.contains("knowledge-notes-active")) return;
      if (getWorkspaceMode() !== "list") return;
      ensureKnowledgeWorkspaceListScrollable();
      setTimeout(ensureKnowledgeWorkspaceListScrollable, 80);
    });
  }

  function renderInlineNotePreview(currentNode, noteContent) {
    var markdown = String(noteContent || "");
    if (!markdown.trim()) {
      return "<div class=\"knowledge-workspace-empty\">" + TEXT.emptyNote + "</div>";
    }
    var anchorPrefix = getKnowledgeNoteAnchorPrefix(currentNode && currentNode.id);
    var headings = extractMdHeadings(markdown);
    var tocHtml = renderFloatingHeadingPanel(headings, anchorPrefix);
    var previewHtml = renderNotePreviewLayout(renderMd(markdown, { anchorPrefix: anchorPrefix }), tocHtml);
    return "<div class=\"knowledge-inline-preview\" data-role=\"knowledge-inline-preview\">" + previewHtml + "</div>";
  }

  function hydrateInlineNotePreview() {
    var preview = document.getElementById("noteSplitPreview");
    if (!preview) return;
    requestAnimationFrame(function () {
      syncActiveNoteToc(preview);
      renderMathInElement(preview);
    });
  }

  function renderNoteMode(currentNode, noteContent) {
    clearGlobalNoteTocDock();
    var previewHtml = noteEditing
      ? renderViewerFrame(currentNode.id, "noteSplitPreview")
      : renderInlineNotePreview(currentNode, noteContent);

    if (noteEditing) {
      return "" +
        "<div class=\"note-split-area\">" +
          "<div class=\"note-split-editor\">" +
            "<div class=\"note-split-label\">" + TEXT.edit +
              "<button onclick=\"saveNoteTypeContent();noteEditing=false;renderNotesByType()\" style=\"float:right;background:#52c41a;color:#fff;border:none;border-radius:4px;padding:2px 10px;cursor:pointer;font-size:12px\">" + TEXT.done + "</button>" +
            "</div>" +
            "<textarea id=\"noteTypeTextarea\" class=\"note-md-textarea\" placeholder=\"# \\u89c4\\u5219\\u603b\\u7ed3&#10;## \\u6613\\u9519\\u70b9&#10;- ...&#10;&#10;## \\u884c\\u52a8\\u5efa\\u8bae&#10;- ...\" oninput=\"liveNotePreview()\">" + escapeHtml(noteContent) + "</textarea>" +
            "<div class=\"note-btn-bar\">" +
              "<button class=\"btn btn-primary btn-sm\" onclick=\"saveNoteTypeContent()\">" + TEXT.save + "</button>" +
              "<span class=\"save-hint\">" + TEXT.shortcutSave + "</span>" +
            "</div>" +
          "</div>" +
          "<div class=\"note-split-preview\">" +
            "<div class=\"note-split-label\">" + TEXT.preview + "</div>" +
            "<div class=\"note-preview-scroll note-preview-frame-scroll\" id=\"noteSplitPreview\">" + previewHtml + "</div>" +
          "</div>" +
        "</div>";
    }

    return "<div class=\"knowledge-workspace-note-wrap\">" +
      "<div class=\"knowledge-workspace-list-head\">" + TEXT.currentNote + "</div>" +
      "<div class=\"note-preview-scroll note-preview-frame-scroll\" id=\"noteSplitPreview\">" + previewHtml + "</div>" +
    "</div>";
  }

  function renderDirectoryMode(currentNode) {
    clearGlobalNoteTocDock();
    var tree = (currentNode.children || []).map(buildDirectoryTree).filter(Boolean);
    var sections = flattenDirectoryTree(tree);
    if (!sections.length) {
      return "<div class=\"knowledge-workspace-note-wrap\">" +
        "<div class=\"knowledge-workspace-list-head\">章节目录</div>" +
        "<div class=\"knowledge-workspace-empty\">当前一级节点下还没有可浏览的子章节。</div>" +
      "</div>";
    }

    var previewNode = getDirectoryPreviewNode(currentNode, sections);
    var previewContent = previewNode ? normalizeKnowledgeNoteMarkdown(previewNode.contentMd) : "";
    var previewHtml = previewNode
      ? renderInlineNotePreview(previewNode, previewContent)
      : "<div class=\"knowledge-workspace-empty\">请选择一个章节查看笔记。</div>";

    var blocks = sections.map(function (section) {
      var isActive = previewNode && section.nodeId === previewNode.id;
      return "<button class=\"knowledge-directory-item" + (isActive ? " active" : "") + (section.hasContent ? "" : " is-structural") + "\" type=\"button\" style=\"padding-left:" + (14 + section.depth * 18) + "px\" onclick=\"openKnowledgeDirectoryNode('" + escapeHtml(section.nodeId) + "')\">" +
        "<span class=\"knowledge-directory-item-title\">" + escapeHtml(section.title) + "</span>" +
        "<span class=\"knowledge-directory-item-meta\">" + section.childCount + "题</span>" +
      "</button>";
    }).join("");

    return "<div class=\"knowledge-workspace-note-wrap knowledge-workspace-note-wrap--directory\">" +
      "<div class=\"knowledge-workspace-list-head\">章节目录</div>" +
      "<div class=\"knowledge-directory-layout\">" +
        "<div class=\"knowledge-directory-list\" id=\"knowledgeDirectoryList\">" + blocks + "</div>" +
        "<div class=\"knowledge-directory-preview-wrap\">" +
          "<div class=\"knowledge-directory-preview-head\">" +
            "<div class=\"knowledge-directory-preview-title\">" + escapeHtml(previewNode ? (previewNode.title || "当前章节") : "当前章节") + "</div>" +
            "<div class=\"knowledge-directory-preview-path\">" + escapeHtml(previewNode ? collapseKnowledgePathTitles(getKnowledgePathTitles(previewNode.id)).join(" > ") : "") + "</div>" +
          "</div>" +
          "<div class=\"note-preview-scroll note-preview-frame-scroll knowledge-directory-preview\" id=\"knowledgeDirectoryPreview\">" + previewHtml + "</div>" +
        "</div>" +
      "</div>" +
    "</div>";
  }

  function renderKnowledgeNotesViewV2() {
    ensureKnowledgeState();
    clearGlobalNoteTocDock();
    var content = document.getElementById("notesContent");
    if (!content) return;
    content.classList.add("knowledge-notes-active");

    var currentNode = getCurrentKnowledgeNode() || getKnowledgeRootNodes()[0];
    if (!currentNode) {
      content.innerHTML = '<div class="knowledge-workspace-empty">' + TEXT.noKnowledgeContent + "</div>";
      return;
    }

    selectedKnowledgeNodeId = currentNode.id;
    notesViewMode = "knowledge";
    var pathText = collapseKnowledgePathTitles(getKnowledgePathTitles(currentNode.id)).join(" > ");
    var linkedCount = countErrorsForKnowledgeNode(currentNode.id, true);
    var directCount = countErrorsForKnowledgeNode(currentNode.id, false);
    var relatedErrors = collectNodeErrors(currentNode);
    var noteContent = normalizeKnowledgeNoteMarkdown(currentNode.contentMd);
    var mode = getWorkspaceMode();
    if (mode === "list" && !relatedErrors.length && noteContent.trim()) {
      mode = "note";
      setWorkspaceMode("note");
    }

    if (!isTopLevelKnowledgeNode(currentNode) && getNoteViewMode() !== "current") {
      setNoteViewMode("current");
    }
    var noteViewMode = isTopLevelKnowledgeNode(currentNode) ? getNoteViewMode() : "current";
    var bodyHtml = mode === "note"
      ? (noteViewMode === "directory" ? renderDirectoryMode(currentNode) : renderNoteMode(currentNode, noteContent))
      : renderListMode(currentNode, relatedErrors);

    content.innerHTML = "<div class=\"knowledge-workspace-shell\">" +
      renderWorkspaceHeader(currentNode, pathText, directCount, linkedCount, relatedErrors.length, mode) +
      bodyHtml +
    "</div>";

    if (mode === "list") {
      bindKnowledgeWorkspaceScrollListener();
      requestAnimationFrame(function () {
        ensureKnowledgeWorkspaceListScrollable();
        setTimeout(ensureKnowledgeWorkspaceListScrollable, 80);
        setTimeout(ensureKnowledgeWorkspaceListScrollable, 260);
        setTimeout(ensureKnowledgeWorkspaceListScrollable, 520);
      });
    }

    syncNotePreviewViewportHeight();

    if (mode === "note" && noteViewMode === "current") {
      if (noteEditing) {
        syncEmbeddedNoteViewers(currentNode, getCurrentNoteMarkdown());
      } else {
        hydrateInlineNotePreview();
      }
    }

    if (mode === "note" && noteViewMode === "current" && noteEditing) {
      bindKnowledgeEditorShortcuts(content);
    }
  }

  function refreshKnowledgeWorkspaceCards() {
    var content = document.getElementById("notesContent");
    if (!content) return;
    if (!content.querySelector(".knowledge-workspace-shell")) return;
    renderKnowledgeNotesViewV2();
  }

  function setKnowledgeWorkspaceMode(mode, editing) {
    setWorkspaceMode(mode);
    if (editing && mode === "note") {
      noteEditing = false;
      renderNotesByType();
      openExternalKnowledgeNoteEditor(selectedKnowledgeNodeId);
      return;
    }
    noteEditing = false;
    renderNotesByType();
  }

  function setKnowledgeNoteViewMode(mode) {
    setNoteViewMode(mode);
    noteEditing = false;
    renderNotesByType();
  }

  function openKnowledgeDirectoryNode(nodeId) {
    if (!nodeId) return;
    noteEditing = false;
    var node = getKnowledgeNodeById(nodeId);
    if (!node) return;
    var targetId = nodeId;
    if (!normalizeKnowledgeNoteMarkdown(node.contentMd).trim()) {
      var descendants = getKnowledgeDescendantNodeIds(node)
        .slice(1)
        .map(function (id) { return getKnowledgeNodeById(id); })
        .filter(function (item) { return item && normalizeKnowledgeNoteMarkdown(item.contentMd).trim(); });
      if (descendants.length) targetId = descendants[0].id;
    }
    setDirectoryPreviewNodeId(targetId);
    renderNotesByType();
  }

  window.addEventListener("message", function (event) {
    if (!event || event.origin !== window.location.origin) return;
    var data = event.data || {};
    if (data.type === "knowledge-note-viewer-size") {
      applyNoteViewerHeight(data.role, data.height);
      syncNotePreviewViewportHeight();
      return;
    }
    if (data.type === "knowledge-note-viewer-ready") {
      var currentNode = getCurrentKnowledgeNode();
      syncNotePreviewViewportHeight();
      if (currentNode) syncEmbeddedNoteViewers(currentNode, getCurrentNoteMarkdown());
      return;
    }
    if (data.type === "knowledge-note-editor-close") {
      closeEmbeddedKnowledgeNoteEditor(true);
      return;
    }
    if (data.type !== "knowledge-note-saved") return;
    noteEditing = false;
    if (data.nodeId) selectedKnowledgeNodeId = data.nodeId;
    renderSidebar();
    renderNotesByType();
    if (typeof renderNotesPanelRight === "function") renderNotesPanelRight();
  });

  window.renderKnowledgeNotesViewV2 = renderKnowledgeNotesViewV2;
  window.getCurrentKnowledgeNode = getCurrentKnowledgeNode;
  window.setCurrentKnowledgeNode = setCurrentKnowledgeNode;
  window.selectKnowledgeLeaf = selectKnowledgeLeaf;
  window.selectNoteType = selectNoteType;
  window.openKnowledgeForError = openKnowledgeForError;
  window.jumpToErrorInList = jumpToErrorInList;
  window.liveNotePreview = liveNotePreview;
  window.saveNoteTypeContent = saveNoteTypeContent;
  window.setKnowledgeWorkspaceMode = setKnowledgeWorkspaceMode;
  window.setKnowledgeNoteViewMode = setKnowledgeNoteViewMode;
  window.openKnowledgeDirectoryNode = openKnowledgeDirectoryNode;
  window.openExternalKnowledgeNoteEditor = openExternalKnowledgeNoteEditor;
  window.refreshKnowledgeWorkspaceCards = refreshKnowledgeWorkspaceCards;
  window.renderNotesByType = function () {
    renderKnowledgeNotesViewV2();
  };
  window.setNotesViewMode = function () {
    setWorkspaceMode("note");
    noteEditing = false;
    renderKnowledgeNotesViewV2();
  };
  window.renderLegacyNotesView = function () {
    setWorkspaceMode("note");
    noteEditing = false;
    renderKnowledgeNotesViewV2();
  };
  window.addEventListener("resize", syncNotePreviewViewportHeight);
})();
/* END: modules/knowledge-workspace.js */

/* BEGIN: modules/knowledge-node-modal.js */
(function () {
  function rerenderKnowledgeShell() {
    renderSidebar();
    renderAll();
    renderNotesByType();
    renderNotesPanelRight();
  }

  function getKnowledgePathOptions(leafOnly, excludeNodeId) {
    var options = [];
    function walk(nodes, trail) {
      (nodes || []).forEach(function (node) {
        var currentTrail = collapseKnowledgePathTitles(trail.concat(node.title));
        var pathLabel = currentTrail.join(" > ");
        if ((!leafOnly || node.isLeaf) && node.id !== excludeNodeId) {
          options.push({ id: node.id, label: pathLabel, node: node });
        }
        if (node.children && node.children.length) {
          walk(node.children, currentTrail);
        }
      });
    }
    walk(getKnowledgeRootNodes(), []);
    return options;
  }

  function getKnowledgeNodeModalTargetOptions(nodeId) {
    return getKnowledgePathOptions(false, nodeId).filter(function (item) {
      return !isKnowledgeDescendant(nodeId, item.id);
    });
  }

  function chooseKnowledgeNodeByPrompt() {
    showToast("编号选择已退到兼容层，当前统一使用弹层搜索和拖拽。", "info");
    return null;
  }

  function addKnowledgeLeafUnderSelected() {
    ensureKnowledgeState();
    var current = getKnowledgeNodeById(selectedKnowledgeNodeId);
    var parent = current || findKnowledgeBranchForModal(true);
    if (!parent) {
      showToast("请先选择一个知识点节点", "warning");
      return;
    }
    var fallback = parent && parent.title ? (parent.title + "补充") : "新知识点";
    openKnowledgeNodeModal("create-child", { parentId: parent.id, fallbackTitle: fallback });
  }

  function openKnowledgeNodeModal(mode, opts) {
    ensureKnowledgeState();
    knowledgeNodeModalState = Object.assign({
      mode: mode,
      nodeId: null,
      parentId: null,
      targetId: null,
      fallbackTitle: "",
      afterSubmit: null
    }, opts || {});

    var titleEl = document.getElementById("knowledgeNodeModalTitle");
    var subtitleEl = document.getElementById("knowledgeNodeModalSubtitle");
    var titleGroup = document.getElementById("knowledgeNodeTitleGroup");
    var titleLabel = document.getElementById("knowledgeNodeTitleLabel");
    var titleInput = document.getElementById("knowledgeNodeTitleInput");
    var targetGroup = document.getElementById("knowledgeNodeTargetGroup");
    var searchInput = document.getElementById("knowledgeNodeTargetSearch");
    if (!titleEl || !subtitleEl || !titleGroup || !titleLabel || !titleInput || !targetGroup || !searchInput) return;

    var node = knowledgeNodeModalState.nodeId ? getKnowledgeNodeById(knowledgeNodeModalState.nodeId) : null;
    var parent = knowledgeNodeModalState.parentId ? getKnowledgeNodeById(knowledgeNodeModalState.parentId) : null;

    if (mode === "rename") {
      if (!node) return;
      titleEl.textContent = "重命名知识点";
      subtitleEl.textContent = "当前节点：" + collapseKnowledgePathTitles(getKnowledgePathTitles(node.id)).join(" > ");
      titleLabel.textContent = "新的节点名称";
      titleInput.value = node.title || "";
      titleGroup.style.display = "";
      targetGroup.style.display = "none";
    } else if (mode === "move") {
      if (!node) return;
      titleEl.textContent = "移动知识点";
      subtitleEl.textContent = "当前节点：" + collapseKnowledgePathTitles(getKnowledgePathTitles(node.id)).join(" > ") + "。请选择新的父节点。";
      titleGroup.style.display = "none";
      targetGroup.style.display = "";
      searchInput.value = "";
      knowledgeNodeModalState.targetId = null;
      renderKnowledgeNodeTargetOptions();
    } else {
      if (!parent) return;
      titleEl.textContent = "新建下级知识点";
      subtitleEl.textContent = "父节点：" + collapseKnowledgePathTitles(getKnowledgePathTitles(parent.id)).join(" > ");
      titleLabel.textContent = "知识点名称";
      titleInput.value = knowledgeNodeModalState.fallbackTitle || "";
      titleGroup.style.display = "";
      targetGroup.style.display = "none";
    }

    openModal("knowledgeNodeModal");
    setTimeout(function () {
      if (mode === "move") searchInput.focus();
      else titleInput.focus();
      if (mode !== "move") titleInput.select();
    }, 10);
  }

  function closeKnowledgeNodeModal() {
    knowledgeNodeModalState = { mode: "", nodeId: null, parentId: null, targetId: null, fallbackTitle: "" };
    closeModal("knowledgeNodeModal");
  }

  function handleKnowledgeNodeTitleKeydown(event) {
    if (event.key === "Enter") {
      event.preventDefault();
      submitKnowledgeNodeModal();
    }
  }

  function renderKnowledgeNodeTargetOptions() {
    var list = document.getElementById("knowledgeNodeTargetList");
    var searchInput = document.getElementById("knowledgeNodeTargetSearch");
    if (!list || !searchInput || knowledgeNodeModalState.mode !== "move") return;

    var keyword = searchInput.value.trim().toLowerCase();
    var filtered = getKnowledgeNodeModalTargetOptions(knowledgeNodeModalState.nodeId).filter(function (item) {
      if (!keyword) return true;
      return item.label.toLowerCase().includes(keyword) || item.node.title.toLowerCase().includes(keyword);
    });

    if (!filtered.length) {
      list.innerHTML = '<div class="knowledge-move-empty">没有匹配的目标知识点</div>';
      return;
    }

    list.innerHTML = filtered.map(function (item) {
      var active = knowledgeNodeModalState.targetId === item.id ? " active" : "";
      return "<div class=\"knowledge-move-item" + active + "\" onclick=\"selectKnowledgeNodeModalTarget('" + item.id + "')\">" +
        "<div class=\"knowledge-move-item-title\">" + escapeHtml(item.node.title) + "</div>" +
        "<div class=\"knowledge-move-item-path\">" + escapeHtml(item.label) + "</div>" +
      "</div>";
    }).join("");
  }

  function selectKnowledgeNodeModalTarget(nodeId) {
    knowledgeNodeModalState.targetId = nodeId;
    renderKnowledgeNodeTargetOptions();
  }

  function moveKnowledgeNodeToTarget(nodeId, targetId, opts) {
    var node = getKnowledgeNodeById(nodeId);
    var target = getKnowledgeNodeById(targetId);
    if (!node || !target) return false;
    if (node.id === target.id) {
      showToast("不能移动到自己", "warning");
      return false;
    }
    if (isKnowledgeDescendant(node.id, target.id)) {
      showToast("不能移动到自己的下级节点", "error");
      return false;
    }

    var oldParent = findKnowledgeParent(node.id);
    if (!oldParent) {
      showToast("一级节点暂不支持移动", "warning");
      return false;
    }

    target.children = target.children || [];
    if (target.children.some(function (item) { return item.id !== node.id && item.title === node.title; })) {
      showToast("目标节点下已存在同名节点", "error");
      return false;
    }

    var oldList = oldParent.children || [];
    var idx = oldList.findIndex(function (item) { return item.id === node.id; });
    if (idx < 0) return false;

    oldList.splice(idx, 1);
    target.children.push(node);
    oldParent.isLeaf = oldList.length === 0;
    target.isLeaf = false;
    expandKnowledgePath(target.id);
    saveKnowledgeState();

    if (!opts || !opts.silent) {
      showToast("节点已移动到：" + collapseKnowledgePathTitles(getKnowledgePathTitles(target.id)).join(" > "), "success");
    }
    setCurrentKnowledgeNode(node.id, { switchTab: false });
    return true;
  }

  function submitKnowledgeNodeModal() {
    var state = knowledgeNodeModalState || {};

    if (state.mode === "rename") {
      var node = getKnowledgeNodeById(state.nodeId);
      if (!node) return;
      var nextTitle = document.getElementById("knowledgeNodeTitleInput") ? document.getElementById("knowledgeNodeTitleInput").value : "";
      var title = normalizeKnowledgeTitle(nextTitle, node.title);
      if (title === node.title) {
        closeKnowledgeNodeModal();
        return;
      }
      var parent = findKnowledgeParent(node.id);
      var siblings = parent ? (parent.children || []) : getKnowledgeRootNodes();
      if (siblings.some(function (item) { return item.id !== node.id && item.title === title; })) {
        showToast("同级下已存在同名节点", "error");
        return;
      }
      node.title = title;
      node.updatedAt = new Date().toISOString();
      saveKnowledgeState();
      closeKnowledgeNodeModal();
      showToast("节点已重命名", "success");
      renderSidebar();
      renderNotesByType();
      renderNotesPanelRight();
      return;
    }

    if (state.mode === "move") {
      if (!state.targetId) {
        showToast("请选择目标父节点", "warning");
        return;
      }
      var moved = moveKnowledgeNodeToTarget(state.nodeId, state.targetId, { silent: false });
      if (moved) closeKnowledgeNodeModal();
      return;
    }

    var createParent = getKnowledgeNodeById(state.parentId);
    if (!createParent) return;
    var rawTitle = document.getElementById("knowledgeNodeTitleInput") ? document.getElementById("knowledgeNodeTitleInput").value : "";
    var childTitle = normalizeKnowledgeTitle(rawTitle, state.fallbackTitle || "新知识点");
    if ((createParent.children || []).some(function (item) { return item.title === childTitle; })) {
      showToast("同级下已存在同名节点", "error");
      return;
    }
    var child = ensureKnowledgeChild(createParent.children, childTitle, (createParent.level || 1) + 1, true);
    if (!child.contentMd) {
      child.contentMd = "# " + child.title + "\n\n";
      child.updatedAt = new Date().toISOString();
    }
    createParent.isLeaf = false;
    ensureKnowledgeNoteRecord(child);
    expandKnowledgePath(createParent.id);
    saveKnowledgeState();
    closeKnowledgeNodeModal();
    if (typeof state.afterSubmit === "function") state.afterSubmit(child);
    setCurrentKnowledgeNode(child.id, { switchTab: false });
    showToast("已新建知识点：" + child.title, "success");
  }

  function renameKnowledgeNode(nodeId) {
    var node = getKnowledgeNodeById(nodeId);
    if (!node) return;
    openKnowledgeNodeModal("rename", { nodeId: node.id });
  }

  function moveKnowledgeNode(nodeId) {
    var node = getKnowledgeNodeById(nodeId);
    if (!node) return;
    if (!getKnowledgeNodeModalTargetOptions(nodeId).length) {
      showToast("暂无可移动到的目标节点", "warning");
      return;
    }
    openKnowledgeNodeModal("move", { nodeId: node.id });
  }

  function deleteKnowledgeNode(nodeId) {
    var node = getKnowledgeNodeById(nodeId);
    var parent = findKnowledgeParent(nodeId);
    if (!node) return;
    if (!parent) {
      showToast("一级节点暂不支持删除", "warning");
      return;
    }
    var directErrors = errors.filter(function (item) { return item.noteNodeId === node.id; });
    var childCount = (node.children || []).length;
    var noteFlag = (node.contentMd || "").trim() ? "\n- 当前节点有笔记内容" : "";
    var childFlag = childCount ? ("\n- 当前节点有 " + childCount + " 个下级，删除后会自动上提到父节点") : "";
    var errorFlag = directErrors.length ? ("\n- 当前节点直属挂了 " + directErrors.length + " 道错题，删除后会自动移动到父节点") : "";
    var ok = confirm("确认删除知识点「" + node.title + "」吗？" + noteFlag + childFlag + errorFlag + "\n\n此操作不可撤销。");
    if (!ok) return;

    var siblings = parent.children || [];
    var idx = siblings.findIndex(function (item) { return item.id === node.id; });
    if (idx < 0) return;

    directErrors.forEach(function (item) { item.noteNodeId = parent.id; });
    siblings.splice.apply(siblings, [idx, 1].concat(node.children || []));
    parent.isLeaf = siblings.length === 0;
    delete knowledgeNotes[node.id];
    knowledgeExpanded.delete(node.id);
    saveKnowledgeExpanded();
    if (selectedKnowledgeNodeId === node.id) selectedKnowledgeNodeId = parent.id;
    saveData();
    saveKnowledgeState();
    rerenderKnowledgeShell();
    showToast("已删除知识点：" + node.title, "success");
  }

  function assignErrorToKnowledgeNode(errorId, targetNodeId, opts) {
    var errorItem = errors.find(function (item) { return item.id === errorId; });
    var targetNode = getKnowledgeNodeById(targetNodeId);
    if (!errorItem || !targetNode) return false;

    var previousNodeId = errorItem.noteNodeId || null;
    errorItem.noteNodeId = targetNode.id;
    saveData();
    saveKnowledgeState();

    if (opts && opts.focusNode) {
      setCurrentKnowledgeNode(targetNode.id, { switchTab: false });
    } else {
      rerenderKnowledgeShell();
    }

    if (!opts || !opts.silent) {
      if (previousNodeId && knowledgeNodeFilter === previousNodeId && previousNodeId !== targetNode.id) {
        showToast("已改挂载到：" + collapseKnowledgePathTitles(getKnowledgePathTitles(targetNode.id)).join(" > ") + "，该题已移出原知识点视图。", "success");
      } else {
        showToast("已改挂载到：" + collapseKnowledgePathTitles(getKnowledgePathTitles(targetNode.id)).join(" > "), "success");
      }
    }
    return true;
  }

  function startKnowledgeNodeDrag(nodeId, event) {
    draggingKnowledgeNodeId = nodeId;
    draggingErrorId = null;
    if (event && event.dataTransfer) {
      event.dataTransfer.effectAllowed = "move";
      event.dataTransfer.setData("text/plain", "knowledge-node:" + nodeId);
    }
    var el = document.querySelector("[data-knowledge-node-id=\"" + nodeId + "\"]");
    if (el) el.classList.add("knowledge-dragging");
  }

  function endKnowledgeNodeDrag() {
    draggingKnowledgeNodeId = null;
    document.querySelectorAll(".knowledge-dragging").forEach(function (el) { el.classList.remove("knowledge-dragging"); });
    document.querySelectorAll(".knowledge-drop-over").forEach(function (el) { el.classList.remove("knowledge-drop-over"); });
  }

  function startErrorDrag(errorId, event) {
    draggingErrorId = errorId;
    draggingKnowledgeNodeId = null;
    if (event && event.dataTransfer) {
      event.dataTransfer.effectAllowed = "move";
      event.dataTransfer.setData("text/plain", "knowledge-error:" + errorId);
    }
  }

  function endErrorDrag() {
    draggingErrorId = null;
    document.querySelectorAll(".knowledge-drop-over").forEach(function (el) { el.classList.remove("knowledge-drop-over"); });
  }

  function allowKnowledgeDrop(event, nodeId) {
    if (!draggingKnowledgeNodeId && !draggingErrorId) return;
    event.preventDefault();
    var el = document.querySelector("[data-knowledge-node-id=\"" + nodeId + "\"]");
    if (el) el.classList.add("knowledge-drop-over");
  }

  function leaveKnowledgeDrop(event) {
    if (event && event.currentTarget) event.currentTarget.classList.remove("knowledge-drop-over");
  }

  function handleKnowledgeDrop(nodeId, event) {
    event.preventDefault();
    event.stopPropagation();
    document.querySelectorAll(".knowledge-drop-over").forEach(function (el) { el.classList.remove("knowledge-drop-over"); });
    if (draggingKnowledgeNodeId) {
      moveKnowledgeNodeToTarget(draggingKnowledgeNodeId, nodeId);
      endKnowledgeNodeDrag();
      return;
    }
    if (draggingErrorId) {
      assignErrorToKnowledgeNode(draggingErrorId, nodeId, { focusNode: true });
      endErrorDrag();
    }
  }

  function moveErrorToKnowledgeNode(errorId, preferredNodeId) {
    var errorItem = errors.find(function (item) { return item.id === errorId; });
    if (!errorItem) return;
    pendingKnowledgeMoveErrorId = errorId;
    pendingKnowledgeMoveTargetId = preferredNodeId || errorItem.noteNodeId || null;
    var currentText = errorItem.noteNodeId
      ? collapseKnowledgePathTitles(getKnowledgePathTitles(errorItem.noteNodeId)).join(" > ")
      : "未关联知识点";
    var currentEl = document.getElementById("knowledgeMoveCurrent");
    if (currentEl) currentEl.textContent = "当前知识点：" + currentText;
    var search = document.getElementById("knowledgeMoveSearch");
    if (search) search.value = "";
    renderKnowledgeMoveOptions();
    openModal("knowledgeMoveModal");
  }

  function closeKnowledgeMoveModal() {
    pendingKnowledgeMoveErrorId = null;
    pendingKnowledgeMoveTargetId = null;
    closeModal("knowledgeMoveModal");
  }

  function renderKnowledgeMoveOptions() {
    var list = document.getElementById("knowledgeMoveList");
    if (!list) return;
    var search = (document.getElementById("knowledgeMoveSearch") ? document.getElementById("knowledgeMoveSearch").value : "").trim().toLowerCase();
    var options = getKnowledgePathOptions(false, null).filter(function (item) {
      if (!search) return true;
      return item.label.toLowerCase().includes(search) || item.node.title.toLowerCase().includes(search);
    });
    if (!options.length) {
      list.innerHTML = '<div class="knowledge-move-empty">没有匹配的知识点</div>';
      return;
    }
    list.innerHTML = options.map(function (item) {
      return "<div class=\"knowledge-move-item " + (item.id === pendingKnowledgeMoveTargetId ? "active" : "") + "\" onclick=\"selectKnowledgeMoveTarget('" + item.id + "')\">" +
        "<div class=\"knowledge-move-item-title\">" + escapeHtml(item.node.title) + "</div>" +
        "<div class=\"knowledge-move-item-path\">" + escapeHtml(item.label) + "</div>" +
        (item.id === getErrorKnowledgeNodeId(pendingKnowledgeMoveErrorId) ? '<div class="knowledge-move-item-current">当前挂载</div>' : "") +
      "</div>";
    }).join("");
  }

  function selectKnowledgeMoveTarget(nodeId) {
    pendingKnowledgeMoveTargetId = nodeId;
    renderKnowledgeMoveOptions();
  }

  function getErrorKnowledgeNodeId(errorId) {
    var errorItem = errors.find(function (item) { return item.id === errorId; });
    return errorItem ? (errorItem.noteNodeId || null) : null;
  }

  function applyKnowledgeMove() {
    var errorItem = errors.find(function (item) { return item.id === pendingKnowledgeMoveErrorId; });
    if (!errorItem) {
      closeKnowledgeMoveModal();
      return;
    }
    if (!pendingKnowledgeMoveTargetId) {
      showToast("请选择目标知识点", "warning");
      return;
    }
    var targetNode = getKnowledgeNodeById(pendingKnowledgeMoveTargetId);
    if (!targetNode) {
      showToast("目标知识点无效", "error");
      return;
    }
    closeKnowledgeMoveModal();
    assignErrorToKnowledgeNode(errorItem.id, targetNode.id, { focusNode: true });
  }

  window.openKnowledgeNodeModal = openKnowledgeNodeModal;
  window.getKnowledgePathOptions = getKnowledgePathOptions;
  window.getKnowledgeNodeModalTargetOptions = getKnowledgeNodeModalTargetOptions;
  window.chooseKnowledgeNodeByPrompt = chooseKnowledgeNodeByPrompt;
  window.addKnowledgeLeafUnderSelected = addKnowledgeLeafUnderSelected;
  window.closeKnowledgeNodeModal = closeKnowledgeNodeModal;
  window.handleKnowledgeNodeTitleKeydown = handleKnowledgeNodeTitleKeydown;
  window.renderKnowledgeNodeTargetOptions = renderKnowledgeNodeTargetOptions;
  window.selectKnowledgeNodeModalTarget = selectKnowledgeNodeModalTarget;
  window.submitKnowledgeNodeModal = submitKnowledgeNodeModal;
  window.renameKnowledgeNode = renameKnowledgeNode;
  window.moveKnowledgeNodeToTarget = moveKnowledgeNodeToTarget;
  window.moveKnowledgeNode = moveKnowledgeNode;
  window.deleteKnowledgeNode = deleteKnowledgeNode;
  window.assignErrorToKnowledgeNode = assignErrorToKnowledgeNode;
  window.startKnowledgeNodeDrag = startKnowledgeNodeDrag;
  window.endKnowledgeNodeDrag = endKnowledgeNodeDrag;
  window.startErrorDrag = startErrorDrag;
  window.endErrorDrag = endErrorDrag;
  window.allowKnowledgeDrop = allowKnowledgeDrop;
  window.leaveKnowledgeDrop = leaveKnowledgeDrop;
  window.handleKnowledgeDrop = handleKnowledgeDrop;
  window.moveErrorToKnowledgeNode = moveErrorToKnowledgeNode;
  window.closeKnowledgeMoveModal = closeKnowledgeMoveModal;
  window.renderKnowledgeMoveOptions = renderKnowledgeMoveOptions;
  window.selectKnowledgeMoveTarget = selectKnowledgeMoveTarget;
  window.getErrorKnowledgeNodeId = getErrorKnowledgeNodeId;
  window.applyKnowledgeMove = applyKnowledgeMove;
})();
/* END: modules/knowledge-node-modal.js */

/* BEGIN: modules/data-management.js */
(function () {
  function rerenderAfterDataChange() {
    renderSidebar();
    renderAll();
    renderNotesByType();
    renderNotesPanelRight();
  }

  function persistClearedErrors() {
    batchSelected = new Set();
    saveData();
    saveReveal();
    rerenderAfterDataChange();
  }

  function deleteErrorsByIds(ids) {
    if (!Array.isArray(ids) || !ids.length) return 0;
    var idSet = new Set(ids);
    var before = errors.length;
    errors = errors.filter(function (item) { return !idSet.has(item.id); });
    ids.forEach(function (id) { revealed.delete(id); });
    persistClearedErrors();
    return before - errors.length;
  }

  function getCurrentModuleContext() {
    if (knowledgeNodeFilter) {
      var node = getKnowledgeNodeById(knowledgeNodeFilter);
      if (!node) return null;
      var ids = new Set(getKnowledgeDescendantNodeIds(node));
      return {
        label: collapseKnowledgePathTitles(getKnowledgePathTitles(node.id)).join(" > "),
        errorIds: errors.filter(function (item) { return ids.has(item.noteNodeId); }).map(function (item) { return item.id; })
      };
    }

    if (selectedKnowledgeNodeId && document.getElementById("tabContentNotes") && document.getElementById("tabContentNotes").classList.contains("active")) {
      var currentNode = getKnowledgeNodeById(selectedKnowledgeNodeId);
      if (!currentNode) return null;
      var currentIds = new Set(getKnowledgeDescendantNodeIds(currentNode));
      return {
        label: collapseKnowledgePathTitles(getKnowledgePathTitles(currentNode.id)).join(" > "),
        errorIds: errors.filter(function (item) { return currentIds.has(item.noteNodeId); }).map(function (item) { return item.id; })
      };
    }

    if (typeFilter) {
      var filtered = errors.filter(function (e) {
        if (typeFilter.level === "type") return e.type === typeFilter.value;
        if (typeFilter.level === "subtype") return e.type === typeFilter.type && e.subtype === typeFilter.value;
        if (typeFilter.level === "sub2") return e.type === typeFilter.type && e.subtype === typeFilter.subtype && e.subSubtype === typeFilter.value;
        return false;
      });
      var label = typeFilter.level === "type"
        ? typeFilter.value
        : typeFilter.level === "subtype"
          ? (typeFilter.type + " > " + typeFilter.value)
          : (typeFilter.type + " > " + typeFilter.subtype + " > " + typeFilter.value);
      return { label: label, errorIds: filtered.map(function (item) { return item.id; }) };
    }

    return null;
  }

  function clearCurrentModuleErrors() {
    var context = getCurrentModuleContext();
    if (!context) {
      showToast("请先选中一个知识点模块或题型筛选。", "warning");
      return;
    }
    if (!context.errorIds.length) {
      showToast("当前模块下没有可删除的题目。", "warning");
      return;
    }
    var ok = confirm("确认清空当前模块题目吗？\n\n模块：" + context.label + "\n题目数：" + context.errorIds.length + "\n\n此操作不可恢复。");
    if (!ok) return;
    var removed = deleteErrorsByIds(context.errorIds);
    showToast("已清空当前模块题目 " + removed + " 道", "success");
  }

  function clearAllErrorsData() {
    if (!errors.length) {
      showToast("当前没有题目可清空。", "warning");
      return;
    }
    var ok = confirm("确认清空全部题目吗？\n\n当前共 " + errors.length + " 道题目。\n\n此操作不可恢复。");
    if (!ok) return;
    var removed = deleteErrorsByIds(errors.map(function (item) { return item.id; }));
    knowledgeNodeFilter = null;
    typeFilter = null;
    showToast("已清空全部题目 " + removed + " 道", "success");
  }

  function resetAllStudyData() {
    var totalErrors = errors.length;
    var totalLegacyNotes = Object.keys(notesByType || {}).length;
    var totalKnowledgeNotes = Object.keys(knowledgeNotes || {}).length;
    var ok = confirm(
      "确认重置全部学习数据吗？\n\n" +
      "- 题目：" + totalErrors + " 道\n" +
      "- 旧题型笔记：" + totalLegacyNotes + " 个\n" +
      "- 知识点笔记：" + totalKnowledgeNotes + " 个\n\n" +
      "账号、目录规则和登录状态会保留。\n此操作不可恢复。"
    );
    if (!ok) return;

    errors = [];
    revealed = new Set();
    notesByType = {};
    noteImages = {};
    globalNote = "";
    knowledgeTree = createDefaultKnowledgeTree();
    knowledgeNotes = {};
    selectedKnowledgeNodeId = null;
    knowledgeNodeFilter = null;
    typeFilter = null;
    noteEditing = false;

    DB.set(KEY_GLOBAL_NOTE, "");
    DB.set(KEY_HISTORY, "[]");
    DB.set(KEY_TODAY_DONE, "0");
    DB.set(KEY_TODAY_DATE, today());
    saveNotesByType();
    saveKnowledgeState();
    persistClearedErrors();

    showToast("全部学习数据已重置", "success");
  }

  window.clearCurrentModuleErrors = clearCurrentModuleErrors;
  window.clearAllErrorsData = clearAllErrorsData;
  window.resetAllStudyData = resetAllStudyData;
})();
/* END: modules/data-management.js */

